const dom = require('../../utils/dom');

const check = {
    id: 'aria-toggle-field-name',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Toggle field has an accessible name',
            fail: 'Toggle field is missing an accessible name. Users cannot identify the control\'s purpose. Add `aria-label` or `aria-labelledby`.'
        }
    },
    selector: '[role="checkbox"], [role="radio"], [role="switch"], [role="menuitemcheckbox"], [role="menuitemradio"]',
    evaluate: function (node) {
        // Toggle fields: checkbox, radio, switch, menuitemcheckbox, menuitemradio
        const name = dom.computeAccessibleName(node);
        if (!name || name.trim() === '') {
            return {
                pass: false,
                message: `Element with role="${node.getAttribute('role')}" does not have an accessible name`
            };
        }
        return { pass: true };
    }
};

module.exports = [check];
