const check = {
    id: 'scrollable-region-focusable',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Scrollable region is focusable',
            fail: 'Scrollable region is not focusable. Keyboard users cannot scroll this content. Add `tabindex="0"` to the scrollable container.'
        }
    },
    evaluate: function (node, options) {
        // Validation:
        // 1. Is scrollable? (scrollHeight > clientHeight or scrollWidth > clientWidth)
        // 2. Is overflow not hidden?
        // 3. Is focusable? (tabindex >= 0 or implicitly focusable)

        // In JSDOM layout is mocked. We can't strictly check scrollHeight absent mocks.
        // We will assume pass unless we detect explicit mismatch in mocked props, or just structure.

        // This check is effectively a placeholder in JSDOM unless test injects dimensions.
        // We will implement logic: if dimensions indicate scroll, verify tabindex.

        if (node.scrollHeight > node.clientHeight || node.scrollWidth > node.clientWidth) {
            const style = node.ownerDocument.defaultView ? node.ownerDocument.defaultView.getComputedStyle(node) : {};
            const overflowX = style.overflowX || style.overflow;
            const overflowY = style.overflowY || style.overflow;

            if (overflowX === 'hidden' && overflowY === 'hidden') return { pass: true }; // Not user-scrollable

            // Check focusability
            const tabindex = node.getAttribute('tabindex');
            if (tabindex && parseInt(tabindex) >= 0) return { pass: true };

            // Interactive elements are naturally focusable
            const tag = node.tagName.toLowerCase();
            const interactiveTags = ['a', 'button', 'input', 'select', 'textarea'];
            if (interactiveTags.includes(tag)) return { pass: true };

            return { pass: false };
        }

        return { pass: true };
    }
};

module.exports = [check];
