const Check = require('../../core/check');

const mediaAudioDescriptionCheck = new Check({
    id: 'media-audio-description-check',
    metadata: {
        messages: {
            pass: 'Video element has an audio description track',
            fail: 'Video element does not have an audio description track'
        }
    },
    evaluate: function (ele) {
        // Check for track element with kind="descriptions"
        const tracks = ele.querySelectorAll('track');
        for (let i = 0; i < tracks.length; i++) {
            if (tracks[i].getAttribute('kind') === 'descriptions') {
                return true;
            }
        }
        return false;
    }
});

module.exports = [mediaAudioDescriptionCheck];
