/**
 * Checks for tabindex
 */
const Check = require('../../core/check');

const tabindexCheck = new Check({
    id: 'tabindex',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element does not have a tabindex greater than 0',
            fail: 'Positive tabindex detected. This disrupts the logical focus order for keyboard users. Use `tabindex="0"` for focusable elements or `-1` for unrelated elements.'
        }
    },
    evaluate: function (node) {
        if (!node.hasAttribute('tabindex')) return true;
        const tabindex = parseInt(node.getAttribute('tabindex'), 10);
        return isNaN(tabindex) || tabindex <= 0;
    }
});

module.exports = [tabindexCheck];
