const check = {
    id: 'aria-valid-attr',
    metadata: {
        impact: 'critical',
        messages: {
            pass: 'ARIA attribute is valid',
            fail: 'Invalid ARIA attribute detected. Assistive technologies do not recognize this attribute. Check the spelling or WAI-ARIA spec.'
        }
    },
    evaluate: function (node, options) {
        const { validAttributes } = require('../../utils/aria-definitions');
        const attributes = node.attributes;
        const invalid = [];

        for (let i = 0; i < attributes.length; i++) {
            const name = attributes[i].name;
            if (name.startsWith('aria-')) {
                if (!validAttributes.includes(name)) {
                    invalid.push(name);
                }
            }
        }

        if (invalid.length > 0) {
            return {
                pass: false,
                message: `Invalid ARIA attributes: ${invalid.join(', ')}`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
