const dom = require('../../utils/dom');

const check = {
    id: 'aria-dialog-name',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Dialog has an accessible name',
            fail: 'Dialog or alertdialog must have an accessible name via aria-label or aria-labelledby'
        }
    },
    selector: '[role="dialog"], [role="alertdialog"]',
    evaluate: function (node) {
        // Must have accessible name
        const name = dom.computeAccessibleName(node);
        if (!name || name.trim() === '') {
            return {
                pass: false,
                message: `Element with role="${node.getAttribute('role')}" does not have an accessible name.`
            };
        }
        return { pass: true };
    }
};

module.exports = [check];
