/**
 * Generates failure summaries for accessibility violations.
 */
const SummaryGenerator = {
    /**
     * Generate a summary string based on check results.
     * @param {Object} nodeResult - The result object for a specific node
     * @returns {string}
     */
    generate: (nodeResult) => {
        if (nodeResult.failureSummary) {
            return nodeResult.failureSummary;
        }

        const messages = [];

        if (nodeResult.any && nodeResult.any.length > 0) {
            messages.push(`Fix any of the following:\n${nodeResult.any.map(c => `  - ${c.message}`).join('\n')}`);
        }

        if (nodeResult.all && nodeResult.all.length > 0) {
            messages.push(`Fix all of the following:\n${nodeResult.all.map(c => `  - ${c.message}`).join('\n')}`);
        }

        if (nodeResult.none && nodeResult.none.length > 0) {
            messages.push(`Fix all of the following:\n${nodeResult.none.map(c => `  - ${c.message}`).join('\n')}`);
        }

        return messages.join('\n\n');
    }
};

module.exports = SummaryGenerator;
