/**
 * Checks for focus-order-semantics
 */
const Check = require('../../core/check');

const focusOrderSemantics = new Check({
    id: 'focus-order-semantics',
    metadata: {
        messages: {
            pass: 'Focus order semantics are valid',
            fail: 'Illogical focus order. The navigation sequence is confusing for keyboard users. Adjust the DOM order or `tabindex` to match the visual layout.'
        }
    },
    evaluate: function (node) {
        // This is always a manual check
        return {
            incomplete: true,
            message: 'Ensure the focus order preserves meaning and operability'
        };
    }
});

module.exports = [focusOrderSemantics];
