const dom = require('../../utils/dom');

const check = {
    id: 'frame-focusable-content',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Frame has no negative tabindex or no focusable content',
            fail: 'Frame with focusable content must not have tabindex="-1"'
        }
    },
    selector: 'iframe, frame',
    evaluate: function (node) {
        // If tabindex is not negative, it's fine (traversable)
        const tabindex = node.getAttribute('tabindex');
        if (!tabindex || parseInt(tabindex, 10) >= 0) return { pass: true };

        // If tabindex is negative, check if it has focusable content
        // We can't easily check cross-origin iframe content, but same-origin we might.
        // In JSDOM/Engine context, we usually assume access or ignore.

        // Axe checks "iframe-focusable-content" - "Using tabindex=-1 on an iframe is common... but if the iframe contains focusable elements, they become unreachable via keyboard".

        // NOTE: In a static analysis context without full browser rendering, we might not see inside the iframe easily unless we load it.
        // If `node.contentDocument` is available?

        try {
            const doc = node.contentDocument || (node.contentWindow && node.contentWindow.document);
            if (!doc) {
                // Can't check content, assume pass or incomplete? 
                // Axe returns "incomplete" if can't access.
                // We'll pass for now to avoid false positives on cross-origin.
                return { pass: true };
            }

            // Check for focusable elements in the frame
            // Using a simplified focusable check (a, button, input...)
            const focusableSelector = 'a[href], button, input, select, textarea, [tabindex]';
            const focusables = doc.querySelectorAll(focusableSelector);

            // Filter out disabled or hidden?
            // dom.isVisible is needed but that runs on node.contentWindow context?

            let hasFocusable = false;
            for (let i = 0; i < focusables.length; i++) {
                const f = focusables[i];
                // Simple visibility check: not hidden attribute or display:none style
                // Deep visibility check is hard across boundaries in simple engine.
                if (!f.hasAttribute('disabled') && !f.hasAttribute('hidden')) {
                    // Check negative tabindex on the element itself?
                    const fTab = f.getAttribute('tabindex');
                    if (!fTab || parseInt(fTab, 10) >= 0) {
                        hasFocusable = true;
                        break;
                    }
                }
            }

            if (hasFocusable) {
                return {
                    pass: false,
                    message: `Frame with tabindex="${tabindex}" contains focusable content`
                };
            }
        } catch (e) {
            // Access denied or error
            return { pass: true };
        }

        return { pass: true };
    }
};

module.exports = [check];
