/**
 * Checks for duplicate-id
 */
const Check = require('../../core/check');

const uniqueId = new Check({
    id: 'id-unique',
    metadata: {
        messages: {
            pass: 'Document has unique ID attributes',
            fail: 'Duplicate ID detected. Assigning the same ID to multiple elements breaks accessibility references (e.g., labels, headers). Ensure all `id` values are unique document-wide.'
        }
    },
    evaluate: function (node) {
        if (!node.id) return true;
        // In a real browser environment, we can check the whole document
        // Note: This might be expensive if run for every node. 
        // Optimization: This check should ideally be run once per document or handled differently.
        // However, following the pattern, we check if there are other elements with the same ID.
        const escapedId = (typeof CSS !== 'undefined' && CSS.escape) ? CSS.escape(node.id) : node.id;
        const root = node.getRootNode ? node.getRootNode() : document;
        const count = root.querySelectorAll('[id="' + escapedId + '"]').length;
        // console.log(`Checking id: ${node.id}, count: ${count}`);
        if (count === 1) return true;

        return {
            incomplete: true,
            message: 'Duplicate ID detected, manual review required'
        };
    }
});

module.exports = [uniqueId];
