/**
 * Checks for select-name
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const selectHasName = new Check({
    id: 'select-has-name',
    metadata: {
        messages: {
            pass: 'Select element has an accessible name',
            fail: 'Select element is missing an accessible label. Users need a label to understand the options. Link a `<label>` using `for` attribute, or use `aria-label`/`aria-labelledby`.'
        }
    },
    evaluate: function (node) {
        return !!dom.computeAccessibleName(node);
    }
});

module.exports = [selectHasName];
