/**
 * Checks for hidden-content
 */
const Check = require('../../core/check');

const hiddenContentCheck = new Check({
    id: 'hidden-content',
    metadata: {
        impact: 'critical',
        messages: {
            pass: 'Hidden content is not focusable',
            fail: 'Focusable content is hidden. Keyboard users can focus on elements that are invisible to screen readers. Remove `aria-hidden="true"` or make the content visible.'
        }
    },
    evaluate: function (node) {
        // Element is aria-hidden="true"
        // Check if it contains any focusable elements
        const focusableSelector = 'a[href], area[href], input:not([disabled]), select:not([disabled]), textarea:not([disabled]), button:not([disabled]), [tabindex="0"]';

        // If the node itself is focusable
        if (node.matches(focusableSelector)) return false;

        // Check children
        const focusableChildren = node.querySelectorAll(focusableSelector);
        return focusableChildren.length === 0;
    }
});

module.exports = [hiddenContentCheck];
