const check = {
    id: 'landmark-unique',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Landmark has a unique role or label',
            fail: 'Landmarks with the same role are indistinguishable. Screen reader users cannot quickly navigate to the correct region. Add unique `aria-label` or `aria-labelledby` to valid landmarks.'
        }
    },
    evaluate: function (node, options) {
        const { landmarkRoles } = require('../../utils/aria-definitions');
        const a11y = require('../../utils/a11y');

        const implicitRoles = {
            'NAV': 'navigation',
            'ASIDE': 'complementary',
            'MAIN': 'main',
            'HEADER': 'banner', // scoped check needed?
            'FOOTER': 'contentinfo', // scoped check needed?
            'FORM': 'form',
            'SECTION': 'region' // only if labeled?
        };

        let role = node.getAttribute('role');
        if (!role) {
            role = implicitRoles[node.tagName];
            if (role === 'banner' || role === 'contentinfo') {
                if (node.closest('article, aside, main, nav, section')) role = null;
            }
            if (role === 'region') {
                if (!a11y.getAccessibleName(node)) role = null;
            }
        }

        if (!role || !landmarkRoles.includes(role)) return { pass: true };

        // Construct selector for this role
        let selector = `[role="${role}"]`;
        if (role === 'navigation') selector += ', nav';
        else if (role === 'complementary') selector += ', aside';
        else if (role === 'main') selector += ', main';
        else if (role === 'form') selector += ', form';
        else if (role === 'banner') selector += ', header'; // Simplified, will filtering loop
        else if (role === 'contentinfo') selector += ', footer';
        // region/section handling is complex for selector, simple approach:

        const candidates = Array.from(document.querySelectorAll(selector));
        // Filter candidates for scoping if needed
        const others = candidates.filter(el => {
            let elRole = el.getAttribute('role');
            if (elRole) return elRole === role;
            // Implicit check again
            if (el.tagName === 'HEADER' && role === 'banner') {
                return !el.closest('article, aside, main, nav, section');
            }
            if (el.tagName === 'FOOTER' && role === 'contentinfo') {
                return !el.closest('article, aside, main, nav, section');
            }
            if (el.tagName === 'SECTION' && role === 'region') {
                if (!el.getAttribute('aria-label') && !el.getAttribute('aria-labelledby')) return false;
            }
            return true;
        });

        if (others.length <= 1) return { pass: true };

        const myLabel = a11y.getAccessibleName(node);
        // Check uniqueness against others
        const duplicate = others.some(other => {
            if (other === node) return false;
            const otherLabel = a11y.getAccessibleName(other);
            // If both have no label, they are duplicates (empty string === empty string)
            return otherLabel === myLabel;
        });

        if (duplicate) {
            return {
                pass: false,
                message: `Landmark with role "${role}" must have a unique label. Duplicate label found: "${myLabel}"`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
