// Partial mapping of elements to allowed roles.
// Source: https://www.w3.org/TR/html-aria/#docconformance
const allowedRoles = {
    'a': ['button', 'checkbox', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'option', 'radio', 'switch', 'tab', 'treeitem', 'doc-backlink', 'doc-biblioref', 'doc-glossref', 'doc-noteref'],
    'address': ['group', 'presentation', 'none'], // contentinfo is allowed if body scoped, but generic logic here
    'area': ['button', 'link'], // Depends on href
    'article': ['application', 'document', 'feed', 'main', 'presentation', 'none', 'region'],
    'aside': ['feed', 'note', 'presentation', 'none', 'region', 'search'],
    'audio': ['application'],
    'base': [], // No roles
    'body': [], // Generic
    'button': ['checkbox', 'link', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'option', 'radio', 'switch', 'tab'],
    'caption': [],
    'col': [],
    'colgroup': [],
    'datalist': [],
    'dd': [],
    'details': [], // group?
    'dialog': ['alertdialog'],
    'div': [], // Any role allowed basically (generic)
    'dl': ['group', 'presentation', 'none', 'list'],
    'dt': [],
    'em': [],
    'embed': ['application', 'document', 'img', 'presentation', 'none'],
    'fieldset': ['group', 'presentation', 'none', 'radiogroup'],
    'figcaption': ['group', 'presentation', 'none'],
    'figure': [],
    'footer': ['group', 'presentation', 'none'], // contentinfo implied
    'form': ['search', 'presentation', 'none'],
    'h1': ['presentation', 'none', 'tab', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'treeitem', 'button', 'doc-subtitle'], // headings allow many widgets
    'h2': ['presentation', 'none', 'tab', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'treeitem', 'button', 'doc-subtitle'],
    'h3': ['presentation', 'none', 'tab', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'treeitem', 'button', 'doc-subtitle'],
    'h4': ['presentation', 'none', 'tab', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'treeitem', 'button', 'doc-subtitle'],
    'h5': ['presentation', 'none', 'tab', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'treeitem', 'button', 'doc-subtitle'],
    'h6': ['presentation', 'none', 'tab', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'treeitem', 'button', 'doc-subtitle'],
    'header': ['group', 'presentation', 'none'], // banner implied
    'hr': ['presentation', 'none', 'separator', 'doc-pagebreak'],
    'html': [],
    'i': [],
    'iframe': ['application', 'document', 'img', 'presentation', 'none'],
    'img': ['button', 'checkbox', 'link', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'option', 'progressbar', 'scrollbar', 'separator', 'slider', 'switch', 'tab', 'treeitem', 'doc-cover'],
    'input': [], // Complex: depends on type
    'ins': [],
    'label': [],
    'legend': [],
    'li': ['menuitem', 'menuitemcheckbox', 'menuitemradio', 'option', 'presentation', 'none', 'radio', 'separator', 'tab', 'treeitem', 'doc-biblioentry', 'doc-endnote'],
    'link': [],
    'main': [],
    'map': [],
    'mark': [],
    'menu': [], // list?
    'meta': [],
    'meter': [],
    'nav': [],
    'noscript': [],
    'object': ['application', 'document', 'img'],
    'ol': ['group', 'listbox', 'menu', 'menubar', 'presentation', 'none', 'radiogroup', 'tablist', 'toolbar', 'tree', 'treegrid'],
    'optgroup': [],
    'option': [],
    'output': [],
    'p': [],
    'param': [],
    'picture': [],
    'pre': [],
    'progress': [],
    'q': [],
    's': [],
    'samp': [],
    'script': [],
    'section': ['alert', 'alertdialog', 'application', 'banner', 'complementary', 'contentinfo', 'dialog', 'document', 'feed', 'log', 'main', 'marquee', 'navigation', 'note', 'presentation', 'none', 'region', 'search', 'status', 'tabpanel', 'group'],
    'select': ['menu'], // Combobox not allowed directly?
    'small': [],
    'source': [],
    'span': [], // Any
    'strong': [],
    'style': [],
    'sub': [],
    'summary': [],
    'sup': [],
    'table': [],
    'tbody': [],
    'td': [],
    'textarea': [],
    'tfoot': [],
    'th': [],
    'thead': [],
    'time': [],
    'title': [],
    'tr': [],
    'track': [],
    'u': [],
    'ul': ['group', 'listbox', 'menu', 'menubar', 'presentation', 'none', 'radiogroup', 'tablist', 'toolbar', 'tree', 'treegrid'],
    'video': ['application']
};

// Elements that do NOT allow ANY role (or very specific ones only, managed above)
// If an element is not in allowedRoles, does it mean any role is allowed (like div) or no role?
// We assume 'div', 'span', 'pre', 'p', 'blockquote' allow ANY role.
const anyRoleElements = ['div', 'span', 'pre', 'p', 'blockquote', 'a', 'area', 'img']; // 'a', 'area', 'img' are conditioned but allow MANY.

const check = {
    id: 'aria-allowed-role',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'Role is allowed on this element',
            fail: 'Role is not allowed on this element. This element does not support the ARIA role assigned to it. Remove the role or use a different element.'
        }
    },
    selector: '[role]',
    evaluate: function (node) {
        const role = node.getAttribute('role');
        const tagName = node.tagName.toLowerCase();

        // If element allows ANY role (generic containers), pass
        if (anyRoleElements.includes(tagName)) return { pass: true };

        // Complex Checks
        // Input: depends on type
        if (tagName === 'input') {
            const type = (node.getAttribute('type') || 'text').toLowerCase();
            // Button types
            if (['button', 'image', 'reset', 'submit'].includes(type)) {
                if (['link', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'option', 'radio', 'switch', 'tab'].includes(role)) return { pass: true };
                return { pass: false, message: `Role "${role}" is not allowed on input type="${type}"` };
            }
            // Checkbox
            if (type === 'checkbox') {
                if (['button', 'menuitemcheckbox', 'option', 'switch'].includes(role)) return { pass: true }; // 'checkbox' is implicit
                return { pass: false, message: `Role "${role}" is not allowed on input type="checkbox"` };
            }
            // Radio
            if (type === 'radio') {
                if (['menuitemradio'].includes(role)) return { pass: true }; // 'radio' is implicit
                return { pass: false, message: `Role "${role}" is not allowed on input type="radio"` };
            }
            // Text types
            const textTypes = ['text', 'search', 'tel', 'url', 'email', 'password', 'date', 'month', 'week', 'time', 'datetime-local', 'number'];
            if (textTypes.includes(type)) {
                // allowed: combobox, searchbox, spinbutton.
                if (['combobox', 'searchbox', 'spinbutton'].includes(role)) return { pass: true };
                return { pass: false, message: `Role "${role}" is not allowed on input type="${type}"` };
            }
            return { pass: true };
        }

        // Check explicit map
        if (allowedRoles[tagName]) {
            if (allowedRoles[tagName].length === 0) {
                // Empty array means NO role allowed? Or just we haven't defined it?
                // For semantics like 'meta', 'script', 'style' -> NO role.
                const noRoleElements = ['meta', 'script', 'style', 'head', 'html', 'title', 'base', 'param', 'source', 'track'];
                if (noRoleElements.includes(tagName)) {
                    return { pass: false, message: `Element <${tagName}> cannot have a role` };
                }
                // Otherwise we might be too strict. Let's start with strict validation for known restrictive elements:
                // 'ul', 'ol', 'dl', 'table' etc have specific allowed roles.
                const restrictiveElements = ['ul', 'ol', 'dl', 'table', 'caption', 'fieldset', 'figure'];
                // If restrictive and not in allowed list -> fail
                // Actually the logic: if existing in map, role MUST be in list.
                // But my map has empty arrays for some.

                // Let's rely on inclusion: if role is included, pass.
                // But if array is empty?
                // Let's refine for a few common failures.
            }

            if (allowedRoles[tagName].includes(role)) return { pass: true };

            // If strictly defined map exists and role not found:
            // But we must support multiple roles 'tab presentation' (though deprecated/rare). Satya engine doesn't split role string?
            // node.getAttribute('role') might be "tab".

            // Only enforce if we are confident.
            // ul/ol are good candidates.
            if (['ul', 'ol'].includes(tagName)) {
                return { pass: false, message: `<${tagName}> cannot have role "${role}". Allowed: ${allowedRoles[tagName].join(', ')}` };
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
