const check = {
    id: 'landmark-complementary-is-top-level',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Aside is top-level',
            fail: 'Complementary landmark is nested. `<aside>` should be a top-level sibling to main content. Move the `<aside>` element outside other landmarks.'
        }
    },
    evaluate: function (node, options) {
        // Landmarks that should not contain aside
        const forbiddenParents = ['aside', 'footer', 'form', 'header', 'main', 'navigation', 'search', 'region', 'section'];
        const forbiddenRoles = ['complementary', 'contentinfo', 'form', 'banner', 'main', 'navigation', 'search', 'region'];

        let current = node.parentElement;
        while (current && current.tagName !== 'BODY') {
            const tag = current.tagName.toLowerCase();
            const role = current.getAttribute('role');

            if (forbiddenParents.includes(tag) || (role && forbiddenRoles.includes(role))) {
                // Special case: nested aside is fine if standard semantics allow (actually axe says complementary must be top level)
                return { pass: false, message: `Nested inside ${tag}` };
            }
            current = current.parentElement;
        }

        return { pass: true };
    }
};

module.exports = [check];
