/**
 * Logger for Satya Engine
 * Handles debug and info logging
 */
class Logger {
    constructor() {
        this.enabled = false;
        this.level = 'INFO'; // DEBUG, INFO, WARN, ERROR
        this.levels = {
            DEBUG: 0,
            INFO: 1,
            WARN: 2,
            ERROR: 3
        };
        this.callback = null;
    }

    /**
     * Configure the logger
     * @param {Object} config 
     */
    configure(config) {
        if (config.enabled !== undefined) {
            this.enabled = config.enabled;
        }
        if (config.level && this.levels[config.level] !== undefined) {
            this.level = config.level;
        }
        if (typeof config.callback === 'function') {
            this.callback = config.callback;
        }
    }

    shouldLog(level) {
        return this.enabled && this.levels[level] >= this.levels[this.level];
    }

    _getCallerInfo() {
        try {
            const err = new Error();
            const stack = err.stack.split('\n');
            // 0: Error, 1: _getCallerInfo, 2: _log, 3: caller (debug/info/etc), 4: actual caller
            if (stack.length > 4) {
                const callerLine = stack[4].trim();
                // Parse "at FunctionName (FileName:Line:Col)" or "at FileName:Line:Col"
                const match = callerLine.match(/at\s+(?:(.+?)\s+\()?(?:(.+?):(\d+):(\d+))\)?/);
                if (match) {
                    return {
                        functionName: match[1] || '<anonymous>',
                        fileName: match[2].split(/[/\\]/).pop(), // Get basename
                        lineNumber: match[3]
                    };
                }
            }
        } catch (e) {
            // Ignore stack trace errors
        }
        return { functionName: 'unknown', fileName: 'unknown', lineNumber: 0 };
    }

    _log(level, message, ...args) {
        if (this.shouldLog(level)) {
            const timestamp = new Date().toISOString();
            const callerInfo = this._getCallerInfo();
            const logData = {
                timestamp,
                level,
                message,
                args,
                ...callerInfo
            };

            const prefix = `[Satya:${level}] [${callerInfo.fileName}:${callerInfo.lineNumber}]`;

            // Console output
            const consoleMethod = console[level.toLowerCase()] || console.log;
            consoleMethod(`${prefix} ${message}`, ...args);

            // Callback output
            if (this.callback) {
                try {
                    this.callback(logData);
                } catch (e) {
                    console.error('Error in logger callback:', e);
                }
            }
        }
    }

    debug(message, ...args) {
        this._log('DEBUG', message, ...args);
    }

    info(message, ...args) {
        this._log('INFO', message, ...args);
    }

    warn(message, ...args) {
        this._log('WARN', message, ...args);
    }

    error(message, ...args) {
        this._log('ERROR', message, ...args);
    }
}

module.exports = new Logger();
