/**
 * Checks for heading-order
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const headingOrder = new Check({
    id: 'heading-order-check',
    metadata: {
        messages: {
            pass: 'Heading order is valid',
            fail: 'Heading order is invalid. Content structure is confusing for screen reader users. Heading levels should only increase by one (e.g., h2 to h3, not h2 to h4).'
        }
    },
    evaluate: function (node, options, virtualNode) {
        // This check requires context of previous heading.
        // For now, we'll implement a simplified version or assume the runner handles context.
        // Since we don't have full context propagation yet in this refactor step,
        // we might need to rely on a more complex check or just pass for now if logic is complex.

        // However, let's try to implement it by querying previous headers in the document.
        // This is expensive but works for now.

        const level = parseInt(node.tagName.substring(1));
        if (isNaN(level)) return true; // Not a heading?

        // Find all headings
        const root = node.getRootNode ? node.getRootNode() : document;
        const allHeadings = Array.from(root.querySelectorAll('h1, h2, h3, h4, h5, h6'))
            .filter(h => dom.isVisible(h));
        const index = allHeadings.indexOf(node);

        if (index > 0) {
            const prevHeading = allHeadings[index - 1];
            const prevLevel = parseInt(prevHeading.tagName.substring(1));
            // Rule: Current level cannot be more than prevLevel + 1
            // Rule: Current level cannot be more than prevLevel + 1
            if (level > prevLevel + 1) {
                return {
                    pass: false,
                    message: `Heading level skipped: <h${level}> follows <h${prevLevel}>. Headings should only increase by one level (e.g., h${prevLevel} -> h${prevLevel + 1}) to maintain a logical structure.`
                };
            }
        }

        return true;
    }
});

module.exports = [headingOrder];
