const dom = require('../../utils/dom');

const check = {
    id: 'duplicate-id-aria',
    metadata: {
        impact: 'critical',
        messages: {
            pass: 'ID is unique or not referenced by ARIA',
            fail: 'Duplicate ID detected in ARIA reference. Accessibility relationships are broken because the ID is not unique. Ensure referenced IDs are unique.'
        }
    },
    selector: '[id]',
    evaluate: function (node) {
        // Goal: Fail if this node's ID is:
        // 1. Duplicated in the document
        // 2. AND Referenced by any ARIA/Label attribute

        const myId = node.id;
        if (!myId) return { pass: true };

        // 1. Check for duplicates
        // Note: querySelectorAll('#' + myId) requires escaping if ID is weird?
        // Standard IDs shouldn't need crazy escaping, but CSS.escape is ideal.
        // Node environment doesn't always have CSS.escape.
        // We can iterate or use attribute selector `[id="..."]` which handles chars better if quoted.

        // We need to find HOW MANY elements have this ID.
        // Optimization: This runs O(N^2) effectively if we query document for every node.
        // But engines usually cache? Satya engine doesn't currently.
        // For performance, we might want to precompute?
        // But logic for 'evaluate' is node-local.

        const duplicates = node.ownerDocument.querySelectorAll(`[id="${myId.replace(/"/g, '\\"')}"]`);
        if (duplicates.length <= 1) {
            return { pass: true }; // Unique
        }

        // 2. Referenced?
        // Only if I am one of the duplicates, does checking reference matter.
        // If I am duplicated, I AM ambiguous.
        // But Axe separates `duplicate-id` from `duplicate-id-aria`.
        // `duplicate-id-aria` only fails if referenced.

        const refSelector = [
            `[aria-labelledby~="${myId}"]`,
            `[aria-describedby~="${myId}"]`,
            `[aria-controls~="${myId}"]`,
            `[aria-owns~="${myId}"]`,
            `[aria-flowto~="${myId}"]`,
            `[aria-activedescendant="${myId}"]`,
            `label[for="${myId}"]`
        ].join(',');

        const isReferenced = node.ownerDocument.querySelector(refSelector);

        if (isReferenced) {
            return { pass: false };
            // Message comes from metadata
        }

        return { pass: true };
    }
};

module.exports = [check];
