const check = {
    id: 'form-field-multiple-labels',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Form field has a single label',
            fail: 'Form field should not have multiple conflicting labels'
        }
    },
    evaluate: function (node, options) {
        let labelCount = 0;

        if (node.hasAttribute('aria-label')) labelCount++;
        if (node.hasAttribute('aria-labelledby')) labelCount++;
        if (node.hasAttribute('title')) labelCount++;

        if (node.id) {
            const explicitLabel = node.ownerDocument.querySelector(`label[for="${node.id}"]`);
            if (explicitLabel) labelCount++;
        }

        const implicitLabel = node.closest('label');
        if (implicitLabel) labelCount++;

        // If implicit label matches explicit label (same element), deduplicate logic would be needed.
        // But implicitly label + explicit label for:id is usually user error or redundant.
        // We fail if > 1.

        if (labelCount > 1) {
            return { pass: false, message: `Field has ${labelCount} labels` };
        }
        return { pass: true };
    }
};

module.exports = [check];
