/**
 * Checks for frame-title
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasTitle = new Check({
    id: 'frame-has-title',
    metadata: {
        messages: {
            pass: 'Frame has an accessible name',
            fail: 'Frame is missing an accessible name. Screen readers rely on the title to describe the frame\'s content. Add a descriptive `title` attribute to the `<iframe>` or `<frame>`.'
        }
    },
    evaluate: function (node) {
        const name = dom.computeAccessibleName(node);
        return !!(name && name.trim().length > 0);
    }
});

module.exports = [hasTitle];
