const check = {
    id: 'aria-redundant-attribute',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'No redundant ARIA attribute found',
            fail: 'Redundant ARIA attribute. The HTML attribute already provides this information. Remove the ARIA attribute (e.g., remove `aria-required` if `required` is present).'
        }
    },
    selector: '[aria-required], [aria-disabled], [aria-readonly]',
    evaluate: function (node) {
        // defined in index.js: selector targets elements with these attrs

        // 1. aria-required
        if (node.hasAttribute('aria-required') && node.getAttribute('aria-required') === 'true') {
            if (node.hasAttribute('required')) {
                return {
                    pass: false,
                    message: 'Attribute "aria-required" is redundant because the "required" attribute is present.'
                };
            }
        }

        // 2. aria-disabled
        if (node.hasAttribute('aria-disabled') && node.getAttribute('aria-disabled') === 'true') {
            if (node.hasAttribute('disabled')) {
                return {
                    pass: false,
                    message: 'Attribute "aria-disabled" is redundant because the "disabled" attribute is present.'
                };
            }
        }

        // 3. aria-readonly
        if (node.hasAttribute('aria-readonly') && node.getAttribute('aria-readonly') === 'true') {
            if (node.hasAttribute('readonly')) {
                return {
                    pass: false,
                    message: 'Attribute "aria-readonly" is redundant because the "readonly" attribute is present.'
                };
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
