const check = {
    id: 'list',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'List has valid children',
            fail: 'List contains invalid children. Screen readers might not announce the list correctly. Lists must only contain `<li>`, `<script>`, or `<template>` elements.'
        }
    },
    selector: 'ul, ol',
    evaluate: function (node) {
        // If list has presentation role, it's not a semantic list.
        const role = node.getAttribute('role');
        if (role === 'presentation' || role === 'none') return { pass: true };

        // Iterate over children
        const children = node.children; // HTMLCollection
        for (let i = 0; i < children.length; i++) {
            const child = children[i];
            const tagName = child.tagName.toLowerCase();

            // Expected tags
            if (['li', 'script', 'template'].includes(tagName)) continue;

            // Also check for element with role="listitem"?
            // Axe strictly requires <li> for native lists, BUT if child has role="listitem" it might be acceptable in some contexts?
            // Actually Axe `list` rule says: "The list rule checks that ul and ol elements only contain li, script or template elements."
            // Simple check.

            return {
                pass: false,
                message: `List contains invalid child: <${tagName}>`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
