const check = {
    id: 'video-description',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Video has description track',
            fail: 'Video is missing audio descriptions. Blind users miss visual details. Add a `<track kind="descriptions">` element.'
        }
    },
    selector: 'video',
    evaluate: function (node) {
        // If it's just audio, ignore? Selector is video.
        // Check for track with kind="descriptions"
        const track = node.querySelector('track[kind="descriptions"]');
        if (track) return { pass: true };

        // Also if the video is purely visual (muted? no audio?), maybe descriptions not needed?
        // But we normally can't detect "silent content" easily.
        // Axe says: "Ensures video elements have audio descriptions".
        // If specific attributes present?
        // Pass if hidden/aria-hidden? Engine handles hidden check usually.

        return {
            pass: false,
            message: 'Video element is missing audio description track'
        };
    }
};

module.exports = [check];
