const Check = require('./check');

class CheckManager {
    constructor() {
        this.checks = new Map();
    }

    /**
     * Register a new check
     * @param {Object} checkConfig 
     */
    addCheck(checkConfig) {
        const check = new Check(checkConfig);
        this.checks.set(check.id, check);
    }

    /**
     * Get a check by ID
     * @param {string} id 
     * @returns {Check}
     */
    getCheck(id) {
        return this.checks.get(id);
    }

    /**
     * Get all registered checks
     * @returns {Check[]}
     */
    getChecks() {
        return Array.from(this.checks.values());
    }
}

module.exports = CheckManager;
