/**
 * Checks for meta-viewport
 */
const Check = require('../../core/check');

const metaViewport = new Check({
    id: 'meta-viewport-check',
    metadata: {
        messages: {
            pass: 'Viewport meta tag does not disable zooming',
            fail: 'Viewport zoom is disabled. Users with low vision cannot enlarge content. Remove `user-scalable=no` and ensure `maximum-scale` is at least 2.0.'
        }
    },
    evaluate: function (node) {
        const content = node.getAttribute('content');
        if (!content) return true;

        // Check for user-scalable=no or maximum-scale < 2
        if (content.includes('user-scalable=no')) return false;
        if (content.includes('maximum-scale')) {
            const match = content.match(/maximum-scale=([0-9.]+)/);
            if (match && parseFloat(match[1]) < 2) return false;
        }
        return true;
    }
});

module.exports = [metaViewport];
