const SummaryGenerator = require('./summary-generator');

class ResultBuilder {
    constructor() {
        this.reset();
    }

    reset() {
        this.violationNodeCounter = 0;
        this.results = {
            testEngine: {
                name: 'satya-engine',
                version: '1.0.0'
            },
            testRunner: {
                name: 'satya'
            },
            testEnvironment: {
                userAgent: typeof navigator !== 'undefined' ? navigator.userAgent : 'unknown',
                windowWidth: typeof window !== 'undefined' ? window.innerWidth : 0,
                windowHeight: typeof window !== 'undefined' ? window.innerHeight : 0,
                orientationType: typeof screen !== 'undefined' && screen.orientation ? screen.orientation.type : 'unknown',
                orientationAngle: typeof screen !== 'undefined' && screen.orientation ? screen.orientation.angle : 0
            },
            timestamp: new Date().toISOString(),
            url: typeof window !== 'undefined' ? window.location.href : '',
            toolOptions: {},
            inapplicable: [],
            passes: [],
            incomplete: [],
            violations: []
        };
    }

    setOptions(options) {
        this.results.toolOptions = options;
    }

    addInapplicable(rule) {
        this.results.inapplicable.push({
            id: rule.id,
            tags: rule.tags,
            description: rule.metadata.description,
            help: rule.metadata.help,
            helpUrl: rule.metadata.helpUrl,
            impact: rule.metadata.impact,
            nodes: []
        });
    }

    addResult(rule, nodeResult, status) {
        const output = {
            id: rule.id,
            impact: rule.metadata.impact,
            tags: rule.tags,
            description: rule.metadata.description,
            help: rule.metadata.help,
            helpUrl: rule.metadata.helpUrl,
            nodes: [nodeResult]
        };

        // Generate failure summary if it's a violation
        if (status === 'fail') {
            this.violationNodeCounter++;
            nodeResult.violationId = this.violationNodeCounter;
            nodeResult.failureSummary = SummaryGenerator.generate(nodeResult);
            this._addToArray(this.results.violations, output, nodeResult);
        } else if (status === 'pass') {
            this._addToArray(this.results.passes, output, nodeResult);
        } else {
            this._addToArray(this.results.incomplete, output, nodeResult);
        }
    }

    _addToArray(array, output, nodeInfo) {
        let existing = array.find(v => v.id === output.id);
        if (!existing) {
            existing = { ...output, nodes: [] };
            array.push(existing);
        }
        existing.nodes.push(nodeInfo);
    }

    getResults() {
        return this.results;
    }

    setMetadata(key, value) {
        this.results[key] = value;
    }
}

module.exports = ResultBuilder;
