const check = {
    id: 'link-in-text-block',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Link is distinguishable from surrounding text',
            fail: 'Link is not distinguishable from surrounding text. Colorblind users might miss this link. Ensure the link has a non-color designator like an underline.'
        }
    },
    evaluate: function (node, options) {
        // Simplified check: if text-decoration is none, fail (unless contrast is high, which we skip).
        // We assume underline is required for now as a strict check.

        const style = node.ownerDocument.defaultView ? node.ownerDocument.defaultView.getComputedStyle(node) : {};
        if (style.textDecoration === 'none' || style.textDecorationLine === 'none') {
            return { pass: false, message: 'Link missing underline' };
        }
        return { pass: true };
    }
};

module.exports = [check];
