const dom = require('../../utils/dom');
const aria = require('../../utils/acc-name');

const check = {
    id: 'label-content-name-mismatch',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element\'s visible text is included in its accessible name',
            fail: 'Accessible name mismatch. Speech control users cannot select the element by its visible text. Ensure the accessible name includes the visible label text.'
        }
    },
    selector: 'a[href], button, [role="link"], [role="button"], [role="checkbox"], [role="menuitem"], [role="menuitemcheckbox"], [role="menuitemradio"], [role="radio"], [role="treeitem"], label, [role="checkbox"], [role="radio"]',
    // Simplified selector for interactive elements that might have label-in-name issues. 
    // Axe uses a broader selector but filters by "supports-name-from-content".
    // We'll target common interactive elements.

    evaluate: function (node) {
        // WCAG 2.5.3 Label in Name
        // For interface components with labels that include text or images of text, the name contains the text that is presented visually.

        // 1. Get visible text
        // Use innerText as a proxy for "visible text".
        // Fallback to textContent for JSDOM if innerText is missing/empty (though innerText is preferred for visibility)
        const visibleText = node.innerText || node.textContent || '';
        const cleanVisibleText = visibleText.trim();

        // If no visible text, this success criterion doesn't apply (it applies to "labels that include text").
        if (!cleanVisibleText) return { pass: true };

        // 2. Get Accessible Name
        // We need a robust ACCNAME calculation. 
        // Assuming aria.computeAccessibleName(node) exists and follows proper precedence (aria-label, aria-labelledby, content, etc.)
        const accName = aria.computeAccessibleName(node) || '';
        const cleanAccName = accName.trim();

        // 3. Comparison
        // "The name contains the text that is presented visually"
        // Case insensitive? WCAG doesn't explicitly say, but usually best practice is case-insensitive.
        // Understanding doc says: "The success criterion is met if the accessible name contains the visible label text."

        if (cleanAccName.toLowerCase().includes(cleanVisibleText.toLowerCase())) {
            return { pass: true };
        }

        return {
            pass: false,
            message: `Accessible name "${cleanAccName}" does not contain visible text "${cleanVisibleText}"`
        };
    }
};

module.exports = [check];
