/**
 * Checks for document-title
 */
const Check = require('../../core/check');

const hasTitle = new Check({
    id: 'doc-has-title',
    metadata: {
        messages: {
            pass: 'Document has a non-empty title',
            fail: 'Document is missing a descriptive title. Screen reader users rely on the title to identify the page. Add a non-empty `<title>` element to the `<head>`.'
        }
    },
    evaluate: function (node) {
        // node is <html> element
        const title = node.querySelector('title');
        return title && title.textContent && title.textContent.trim().length > 0;
    }
});

module.exports = [hasTitle];
