const dom = require('../../utils/dom');

const check = {
    id: 'target-size',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element has sufficient target size',
            fail: 'Element is too small. Increase the size to at least 24x24 CSS pixels.'
        }
    },
    selector: 'a[href], button, input, select, textarea, [role="button"], [role="link"], [role="menuitem"], [role="option"], [role="radio"], [role="checkbox"], [role="switch"], [role="tab"]',
    evaluate: function (node) {
        // WCAG 2.5.8 Target Size (Minimum)
        // The size of the target for pointer inputs is at least 24 by 24 CSS pixels.

        // Check 1: User Agent Control?
        // If the target is in a sentence or block of text (inline), it might be exempt? 
        // Or if size is determined by user agent and not modified by author.
        // We'll skip complex exception logic for now and flag small targets.

        // Get dimensions
        const width = node.offsetWidth;
        const height = node.offsetHeight;

        // JSDOM fallback: if 0, we can't really fail it safely unless we are sure it's 0 (display:none is hidden anyway).
        // dom.isVisible already checks for 0x0?
        // If dom.isVisible passes, but size is < 24, we flag.

        // If width or height is 0, it shouldn't be visible. Wait dom.isVisible checks that.
        // So if we are here, element is visible.

        const minSize = 24;

        if (width < minSize || height < minSize) {
            return {
                pass: false,
                message: `Element size is ${width}x${height} px, expected at least 24x24 px`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
