const v1 = require('./v1');
const v2 = require('./v2');

const reporters = {
    v1,
    v2
};

/**
 * Get a reporter by name
 * @param {String} name 
 * @returns {Function} Reporter function
 */
function getReporter(name) {
    if (typeof name === 'function') {
        return name;
    }
    
    if (reporters[name]) {
        return reporters[name];
    }
    
    // Default to v1 if not found or not specified
    return reporters.v1;
}

module.exports = {
    getReporter
};
