const check = {
    id: 'aria-valid-attr-value',
    metadata: {
        impact: 'critical',
        messages: {
            pass: 'ARIA attribute values are valid',
            fail: 'Invalid ARIA attribute value. Screen readers may ignore the attribute or behave unexpectedly. Fix the value to match the WAI-ARIA specification.'
        }
    },
    evaluate: function (node, options) {
        const { attributeValues, validAttributes } = require('../../utils/aria-definitions');
        const attributes = node.attributes;
        const invalidAttrs = [];

        for (let i = 0; i < attributes.length; i++) {
            const attrName = attributes[i].name;
            const attrValue = attributes[i].value;

            if (validAttributes.includes(attrName) && attributeValues[attrName]) {
                const config = attributeValues[attrName];
                const type = config.type;
                let isValid = true;
                let expected = '';

                switch (type) {
                    case 'boolean':
                        const boolValues = ['true', 'false'];
                        if (config.allowUndefined) boolValues.push('undefined');
                        isValid = boolValues.includes(attrValue.toLowerCase());
                        expected = `one of: ${boolValues.join(', ')}`;
                        break;
                    case 'token':
                        isValid = config.values.includes(attrValue.toLowerCase());
                        expected = `one of: ${config.values.join(', ')}`;
                        break;
                    case 'tokenlist':
                        const tokens = attrValue.toLowerCase().split(/\s+/);
                        isValid = tokens.every(t => config.values.includes(t));
                        expected = `list of tokens from: ${config.values.join(', ')}`;
                        break;
                    case 'integer':
                        const intVal = parseInt(attrValue, 10);
                        isValid = !isNaN(intVal) && intVal.toString() === attrValue.trim();
                        if (isValid && config.min !== undefined) {
                            isValid = intVal >= config.min;
                        }
                        expected = 'an integer' + (config.min !== undefined ? ` >= ${config.min}` : '');
                        break;
                    case 'number':
                        const numVal = parseFloat(attrValue);
                        isValid = !isNaN(numVal) && isFinite(numVal);
                        expected = 'a number';
                        break;
                    case 'id':
                    case 'idlist':
                        // Basic check: should not be empty
                        if (attrValue.trim().length === 0) {
                            isValid = false;
                            expected = 'a non-empty ID or ID list';
                        } else {
                            // Check if referenced IDs exist
                            const ids = attrValue.trim().split(/\s+/);
                            const root = node.getRootNode ? node.getRootNode() : (node.ownerDocument || document);
                            if (root) {
                                const missingIds = ids.filter(id => !root.getElementById(id));
                                if (missingIds.length > 0) {
                                    isValid = false;
                                    expected = `referenced IDs to exist on the page (missing: ${missingIds.join(', ')})`;
                                }
                            }
                        }
                        break;
                    case 'string':
                        // Strings are generally always valid unless completely empty when required?
                        // ARIA spec usually allows empty strings for some, but not for others.
                        // For now, assume a string is valid if it exists.
                        isValid = true;
                        break;
                }

                if (!isValid) {
                    invalidAttrs.push(`${attrName}="${attrValue}" (expected ${expected})`);
                }
            }
        }

        if (invalidAttrs.length > 0) {
            return {
                pass: false,
                message: `The following ARIA attributes have invalid values: ${invalidAttrs.join(', ')}`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
