const check = {
    id: 'th-has-data-cells',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Table header refers to data cells',
            fail: 'Table header does not refer to any data cells. Empty or broken headers confuse screen reader users. Ensure `<th>` elements identify columns or rows containing data.'
        }
    },
    evaluate: function (node, options) {
        let table = node.closest('table');
        if (!table && node.getAttribute('role') === 'columnheader') {
            table = node.closest('[role="table"], [role="grid"]');
        }

        if (!table) return { pass: true }; // Not in a table context?

        // Check if table has any data cells
        const dataCells = table.querySelectorAll('td, [role="cell"], [role="gridcell"]');
        if (dataCells.length > 0) {
            return { pass: true };
        }

        return { pass: false };
    }
};

module.exports = [check];
