/**
 * Checks for skip-link
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const skipLink = new Check({
    id: 'skip-link',
    metadata: {
        messages: {
            pass: 'Page has a valid skip link',
            fail: 'Page is missing a skip-to-content link. Keyboard users cannot bypass repeated navigation. Add a visible link (e.g., "Skip to main content") at the top of the page pointing to the main content.'
        }
    },
    evaluate: function (node) {
        // Find visible links that point to an anchor on the same page
        const links = dom.$$('a[href^="#"]', node);

        // Filter for "skip" in text
        const validSkipLink = links.find(link => {
            const text = (link.textContent || '').toLowerCase();
            if (!text.includes('skip')) return false;

            // Check if visible (using dom.isVisible or simplistic check)
            // Skip links are often hidden until focused, but they must be reachable.
            // For now, let's assume they exist in DOM.

            // Check target
            const id = link.getAttribute('href').slice(1);
            if (!id) return false;

            const target = node.ownerDocument.getElementById(id);
            return !!target;
        });

        return !!validSkipLink;
    }
});

module.exports = [skipLink];
