/**
 * Checks for html-xml-lang-mismatch
 */
const Check = require('../../core/check');

const htmlXmlLangMismatch = new Check({
    id: 'html-xml-lang-mismatch',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'The lang and xml:lang attributes match',
            fail: 'Language attribute mismatch. Inconsistent `lang` and `xml:lang` values confuse screen readers. Ensure both attributes specify the same language code.'
        }
    },
    evaluate: function (node) {
        if (!node.hasAttribute('lang') || !node.hasAttribute('xml:lang')) return true;

        const lang = node.getAttribute('lang').toLowerCase();
        const xmlLang = node.getAttribute('xml:lang').toLowerCase();

        return lang === xmlLang;
    }
});

module.exports = [htmlXmlLangMismatch];
