/**
 * Checks for video-caption
 */
const Check = require('../../core/check');

const hasCaptions = new Check({

    id: 'video-caption',
    metadata: {
        messages: {
            pass: 'Video element has captions',
            fail: 'Video is missing captions. Deaf and hard-of-hearing users cannot consume the audio content. Provide a `<track>` element with `kind="captions"`.'
        }
    },
    evaluate: function (node) {

        // Muted videos don't need captions
        if (node.muted || node.hasAttribute('muted')) return true;

        const tracks = node.querySelectorAll('track[kind="captions"]');
        if (tracks.length > 0) return true;

        return {
            incomplete: true,
            message: 'Video captions not found, manual review required'
        };
    }
});

module.exports = [hasCaptions];
