/**
 * Checks for scope-attr-valid
 */
const Check = require('../../core/check');

const scopeAttrValid = new Check({
    id: 'scope-attr-valid',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'The scope attribute is used correctly',
            fail: 'The `scope` attribute is invalid. Invalid scope values are ignored by screen readers. Use `row`, `col`, `rowgroup`, or `colgroup`, and only on `<th>` elements.'
        }
    },
    evaluate: function (node) {
        if (!node.hasAttribute('scope')) return true;
        // Scope only allowed on th elements
        if (node.tagName.toLowerCase() !== 'th') return false;

        const scope = node.getAttribute('scope').toLowerCase();
        const validScopes = ['row', 'col', 'rowgroup', 'colgroup'];
        return validScopes.includes(scope);
    }
});

module.exports = [scopeAttrValid];
