const dom = require('../../utils/dom');

const check = {
    id: 'aria-roledescription',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element has a semantic role supporting aria-roledescription',
            fail: 'Element has no semantic role or has a generic/presentation role'
        }
    },
    selector: '[aria-roledescription]',
    evaluate: function (node) {
        // Must have semantic role
        const role = node.getAttribute('role');
        const tagName = node.tagName.toLowerCase();

        // 1. Check explicit role
        if (role) {
            // Presentation/none/generic should not support roledescription?
            // Actually, if role="presentation", aria-roledescription is invalid because it tries to give a name to something removed from tree.
            // Axe checks "role-supports-aria-roledescription" -> must not be abstract, must be semantic.
            const ignoredRoles = ['presentation', 'none', 'generic']; // generic is new in ARIA 1.3? or just <div> defaults to generic.

            if (ignoredRoles.includes(role)) {
                return { pass: false, message: `Element with role="${role}" cannot support aria-roledescription` };
            }
            return { pass: true };
        }

        // 2. Check implicit role
        // If no explicit role, does element have implicit semantic role?
        // Div and Span have no implicit role (or generic).
        if (tagName === 'div' || tagName === 'span') {
            return { pass: false, message: `<${tagName}> has no implicit semantic role and requires an explicit role to support aria-roledescription` };
        }

        // Other elements usually have semantic role (p, h1, button, etc)
        // We could be exhaustive but detecting "no semantic role" is hard without a full map.
        // Axe checks "has-global-aria-role" or "has-widget-role" etc.
        // For Satya: we assume standard HTML elements (except div/span) have semantics or don't matter as much.
        // But strictly, we should flagging <div>/<span>.

        return { pass: true };
    }
};

module.exports = [check];
