const focusUtils = require('../utils/focus-utils');
const dom = require('../utils/dom');

class FocusAnalyzer {
    /**
     * Get the tab order of elements within a root
     * @param {HTMLElement} root 
     * @returns {Array<{element: HTMLElement, selector: string, order: number, tabIndex: number}>}
     */
    static getTabOrder(root) {
        // 1. Collect all tabbable elements (depth-first)
        // We use a tree walker or simple querySelectorAll('*') and filter
        // Using dom.$$ helper if available or simple Array.from

        let allElements = [];
        if (root.querySelectorAll) {
            allElements = Array.from(root.querySelectorAll('*'));
        }

        // Include root if it is tabbable
        if (focusUtils.isTabbable(root)) {
            allElements.unshift(root);
        }

        const tabbables = allElements.filter(el => focusUtils.isTabbable(el));

        // 2. Separate into groups
        const regularTab = []; // tabindex = 0 or implicit
        const positiveTab = []; // tabindex > 0

        tabbables.forEach((el, index) => {
            const rawIndex = el.getAttribute('tabindex');
            const tabIndex = rawIndex ? parseInt(rawIndex, 10) : 0;

            const item = {
                element: el,
                selector: dom.getSelector(el),
                tabIndex: tabIndex, // normalized to 0 for implicit
                documentOrder: index // preserve relative document order
            };

            if (tabIndex > 0) {
                item.tabIndex = tabIndex;
                positiveTab.push(item);
            } else {
                item.tabIndex = 0;
                regularTab.push(item);
            }
        });

        // 3. Sort positive tab indexes
        // Logic: Ascending tab index value. If equal, document order.
        positiveTab.sort((a, b) => {
            if (a.tabIndex === b.tabIndex) {
                return a.documentOrder - b.documentOrder;
            }
            return a.tabIndex - b.tabIndex;
        });

        // Regular tab indexes are already in document order

        // 4. Concatenate: Positive first, then Regular
        const finalOrder = [...positiveTab, ...regularTab];

        // 5. Assign ordinal
        return finalOrder.map((item, idx) => ({
            ...item,
            order: idx + 1
        }));
    }
}

module.exports = FocusAnalyzer;
