/**
 * Checks for dlitem
 */
const Check = require('../../core/check');

const dlitem = new Check({
    id: 'dlitem',
    metadata: {
        messages: {
            pass: 'Description list item has a valid parent',
            fail: 'Description list item is orphaned. Screen readers effectively ignore isolated items. `<dt>` and `<dd>` elements must be children of a `<dl>`.'
        }
    },
    evaluate: function (node) {
        let parent = node.parentElement;
        while (parent) {
            if (parent.tagName === 'DL') return true;
            // Allowed wrapping container
            if (parent.tagName === 'DIV' || parent.tagName === 'TEMPLATE' || parent.tagName === 'SCRIPT') {
                parent = parent.parentElement;
                continue;
            }
            return false;
        }
        return false;
    }
});

module.exports = [dlitem];
