const Check = require('../../core/check');

const uniqueAccessKeys = new Check({
    id: 'accesskeys',
    metadata: {
        messages: {
            pass: 'Accesskey attribute is unique',
            fail: 'Duplicate accesskey detected. Using the same accesskey for multiple elements causes conflicts for keyboard users. Ensure all `accesskey` values are unique.'
        }
    },
    evaluate: function (node) {
        const key = node.getAttribute('accesskey');
        if (!key) return true;

        // Find all elements with the same accesskey
        const allElements = document.querySelectorAll(`[accesskey="${key}"]`);

        // If more than one element has this key, fail
        return allElements.length === 1;
    }
});

module.exports = [uniqueAccessKeys];
