const dom = require('../../utils/dom');

const check = {
    id: 'aria-text',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element with role="text" has no focusable descendants',
            fail: 'Focusable content inside `role="text"`. This role flattens content, making focusable descendants inaccessible. Remove `role="text"` or move focusable elements outside.'
        }
    },
    selector: '[role="text"]',
    evaluate: function (node) {
        // role="text" flattens the accessibility tree for the element and its descendants.
        // It makes the element behave like a text node.
        // If it contains focusable elements, they become inaccessible (cannot be reached or operated properly via AT).

        // We need to check if there are any focusable descendants.
        // We can use a focusable selector.
        // Common focusable elements: a[href], button, input, select, textarea, [tabindex]

        const focusableSelector = 'a[href], area[href], input:not([disabled]), select:not([disabled]), textarea:not([disabled]), button:not([disabled]), iframe, object, embed, [tabindex="0"], [contenteditable]';

        const focusableDescendants = node.querySelectorAll(focusableSelector);

        // Filter out those with tabindex="-1" if querySelectorAll captured them (tabindex="0" selector avoids -1 but broad [tabindex] might catch it)
        // Our selector above uses [tabindex="0"], but we should also check for any explicit tabindex which makes it focusable?
        // Actually, elements with tabindex="-1" are programmatically focusable but not in tab order.
        // role="text" flattening might prevent programmatic focus too if it hides children.
        // Axe checks "allow-focus".

        // Let's iterate and verify strict focusability.
        for (let i = 0; i < focusableDescendants.length; i++) {
            const el = focusableDescendants[i];
            if (el.nodeType !== 1) continue;
            if (el === node) continue;
            if (dom.isVisible(el)) {
                return { pass: false, message: 'Element with role="text" contains a focusable descendant: ' + el.tagName };
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
