const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasAlt = new Check({
    id: 'input-image-alt',
    metadata: {
        messages: {
            pass: 'Image input has accessible text',
            fail: 'Image input is missing alternative text. Screen readers cannot convey the purpose of this button. Add an `alt` attribute describing the button\'s action.'
        }
    },
    evaluate: function (node) {
        return !!dom.computeAccessibleName(node);
    }
});

module.exports = [hasAlt];
