const dom = require('../../utils/dom');

const check = {
    id: 'empty-table-header',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'Table header contains text',
            fail: 'Empty table header detected. Screen readers cannot identify the column or row purpose. Add descriptive text to the `<th>` element.'
        }
    },
    selector: 'th',
    evaluate: function (node) {
        // Must contain visible text or accessible name
        // Use accessible name computation or simple text checks

        // 1. Accessible Name
        const name = dom.computeAccessibleName(node);
        if (name && name.trim().length > 0) return { pass: true };

        // 2. Visible text logic (if acc name fails, usually text also fails unless hidden)
        // If no accessible name, it's likely empty.

        return {
            pass: false,
            message: 'Table header is empty'
        };
    }
};

module.exports = [check];
