const dom = require('../../utils/dom');

const check = {
    id: 'aria-tooltip-name',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'ARIA tooltip has an accessible name',
            fail: 'Tooltip is missing an accessible name. Screen readers cannot describe the tooltip. Add `aria-label` or `aria-labelledby`.'
        }
    },
    evaluate: function (node, options) {
        const name = dom.computeAccessibleName(node);
        return {
            pass: !!(name && name.trim().length > 0)
        };
    }
};

module.exports = [check];
