/**
 * Rule definition for Satya Engine
 */
class Rule {
    constructor(config) {
        this.id = config.id;
        this.selector = config.selector;
        this.metadata = config.metadata || {};
        this.tags = config.tags || [];

        // Check groups
        this.any = config.any || [];
        this.all = config.all || [];
        this.none = config.none || [];

        this.enabled = config.enabled;
        this.includeHidden = config.includeHidden || false;

        // Legacy support (to be migrated)
        this.check = config.check;
        this.runFn = config.run;
    }

    /**
     * Check if the rule matches the given element
     * @param {HTMLElement} element 
     * @param {Object} utils - Selector utilities
     * @returns {boolean}
     */
    matches(element, utils) {
        if (!this.selector) return true;
        // Use utils.matches if available, otherwise native matches
        if (utils && utils.matches) {
            return utils.matches(element, this.selector);
        }
        return element.matches(this.selector);
    }
}

module.exports = Rule;
