const { computeAccessibleName } = require('./acc-name');

const Selector = require('./selector');

const dom = {
    /**
     * Compute accessible name
     */
    computeAccessibleName,

    /**
     * Check if element matches selector (enhanced)
     */
    matches: (element, selector) => Selector.matches(element, selector),

    /**
     * Checks if an element is visible in the DOM.
     * @param {HTMLElement} element
     * @returns {boolean}
     */
    isVisible: (element) => {
        if (!element) return false;
        // Check if window is available (browser environment)
        if (typeof window === 'undefined') {
            // Check if element has ownerDocument and defaultView (e.g. JSDOM in Node)
            if (element.ownerDocument && element.ownerDocument.defaultView) {
                // It's a node in valid context, continue
            } else {
                return true; // Fallback for non-browser envs if any
            }
        }

        const win = element.ownerDocument ? element.ownerDocument.defaultView : undefined;
        if (!win) return true; // Fallback if no window (e.g. detached)

        // Check ancestry for hidden attributes
        let current = element;
        while (current && current.nodeType === 1) {
            const style = win.getComputedStyle(current);

            // Special handling for <area> elements:
            // They are technically display:none in CSS ,
            // but for accessibility purposes they are considered visible hit targets (if map is used).
            // We skip the display:none check for the area element itself.
            const isArea = current.tagName.toLowerCase() === 'area';

            if (!isArea && (style.display === 'none' || style.visibility === 'hidden')) return false;

            if (current.hasAttribute('hidden')) return false;
            if (current.getAttribute('aria-hidden') === 'true') return false;
            current = current.parentElement;
        }

        // Check dimensions (only for the element itself, as parents might have dimensions but hide children via overflow, but display:none is handled above)
        // Note: In JSDOM, offsetWidth is 0 for children of display:none, but we mocked it.
        // However, if we check ancestry for display:none explicitly, we cover that case even if JSDOM/mock is weird.
        // But we still need to check dimensions for cases like width:0; height:0;
        // Exception: area elements are always 0x0 but are considered visible/interactive
        const tagName = element.tagName.toLowerCase();
        if (tagName === 'area') return true;
        if (tagName === 'input' && element.type === 'image') return true;
        if (tagName === 'object') return true;

        if (element.offsetWidth === 0 && element.offsetHeight === 0 && element.getClientRects().length === 0) return false;

        return true;
    },

    /**
     * Query selector all that returns an array.
     * @param {string} selector
     * @param {HTMLElement|Document} context
     * @returns {HTMLElement[]}
     */
    $$: (selector, context = document) => {
        return Array.from(context.querySelectorAll(selector));
    },

    /**
     * Get a unique selector for an element
     * @param {HTMLElement} element 
     * @returns {string}
     */
    getSelector: (element) => {
        if (!element) return '';
        if (element.nodeType !== 1) return '';

        const path = [];
        let current = element;

        while (current) {
            // Determine if we are in Shadow DOM
            const rootNode = current.getRootNode();
            const isInShadow = (rootNode && rootNode.nodeType === 11);

            let selector = '';

            if (current.id) {
                selector = '#' + current.id;
                // If in light DOM, we can stop here.
                // If in shadow DOM, we use this selector but MUST continue to the host.
                if (!isInShadow) {
                    path.unshift(selector);
                    break;
                }
            } else {
                let tagName = current.tagName.toLowerCase();
                selector = tagName;

                // Check siblings for same tag (context aware)
                // Handle shadow root (no parentElement but has parentNode if not detached) or standard parent
                const parent = current.parentElement || (current.parentNode && current.parentNode.nodeType === 11 ? null : current.parentNode);

                if (parent) {
                    const siblings = Array.from(parent.children).filter(e => e.tagName.toLowerCase() === tagName);
                    if (siblings.length > 1) {
                        const index = Array.from(parent.children).indexOf(current) + 1;
                        selector += `:nth-child(${index})`;
                    }
                }
            }

            path.unshift(selector);

            // Move up
            if (current.parentElement) {
                current = current.parentElement;

                // Stop at HTML if we reached it
                if (current.tagName.toLowerCase() === 'html') {
                    path.unshift('html');
                    break;
                }
            } else if (current.parentNode && current.parentNode.nodeType === 11) {
                // We reached the Shadow Root.
                // Next step is the Host element.
                // Add a visual separator for the boundary.
                path.unshift('::shadow-root');
                current = current.parentNode.host;
            } else {
                // Detached or document root
                break;
            }
        }

        return path.join(' > ');
    },

    /**
     * Get a code snippet for the element
     * @param {HTMLElement} element
     * @returns {string}
     */
    getSnippet: (element) => {
        if (!element || element.nodeType !== 1) return '';

        const outer = element.outerHTML;
        // If short enough, return full
        if (outer.length <= 150) return outer;

        const clone = element.cloneNode(false);
        const cloneOuter = clone.outerHTML;
        const tagName = element.tagName.toLowerCase();

        // Void elements don't have closing tags
        const voidElements = ['area', 'base', 'br', 'col', 'embed', 'hr', 'img', 'input', 'link', 'meta', 'param', 'source', 'track', 'wbr'];

        if (voidElements.includes(tagName)) {
            return cloneOuter;
        }

        // Attempt to insert ... inside the empty clone
        const closingIndex = cloneOuter.lastIndexOf('</');
        if (closingIndex !== -1) {
            return cloneOuter.substring(0, closingIndex) + '...' + cloneOuter.substring(closingIndex);
        }

        return cloneOuter;
    },

    /**
     * Get bounding client rect safely
     * @param {HTMLElement} element 
     * @returns {Object|null}
     */
    getRect: (element) => {
        if (!element || typeof element.getBoundingClientRect !== 'function') return null;
        try {
            const rect = element.getBoundingClientRect();
            // Return a POJO, not the DOMRect object which might not serialize well in some envs
            return {
                x: Math.round(rect.x),
                y: Math.round(rect.y),
                width: Math.round(rect.width),
                height: Math.round(rect.height),
                top: Math.round(rect.top),
                right: Math.round(rect.right),
                bottom: Math.round(rect.bottom),
                left: Math.round(rect.left)
            };
        } catch (e) {
            return null;
        }
    }
};

module.exports = dom;
