const dom = require('../../utils/dom');

const check = {
    id: 'link-ambiguous-text',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Link text is descriptive',
            fail: 'Link text is ambiguous. Screen reader users navigating out of context won\'t understand the destination. Use descriptive text meaningfully (avoid "click here", "read more" without context).'
        }
    },
    selector: 'a[href], [role="link"]',
    evaluate: function (node) {
        const ambiguousPhrases = [
            'click here',
            'read more',
            'learn more',
            'more',
            'here',
            'link',
            'go',
            'info',
            'click',
            'this link',
            'continue'
        ];

        let accName = '';
        if (dom && dom.computeAccessibleName) {
            accName = dom.computeAccessibleName(node);
        } else {
            // Fallback to text content if util missing
            accName = node.textContent || '';
        }

        accName = accName.trim().toLowerCase();

        // Remove non-alphanumeric chars for comparison? 
        // e.g. "Read more..." -> "read more"
        const cleanName = accName.replace(/[^a-z0-9 ]/g, '').trim();

        if (ambiguousPhrases.includes(cleanName)) {
            return {
                pass: false,
                message: `The link text "${accName}" is ambiguous.`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
