const Check = require('../../core/check');

const autocompleteValidCheck = new Check({
    id: 'autocomplete-valid-check',
    metadata: {
        messages: {
            pass: 'Autocomplete attribute has a valid value',
            fail: 'Invalid `autocomplete` value. Browsers cannot correctly autofill the field. Use standard values like `name`, `email`, or `one-time-code`.'
        }
    },
    evaluate: function (ele) {
        const autocomplete = ele.getAttribute('autocomplete');
        if (!autocomplete) {
            return true; // Should be handled by selector, but safe guard
        }

        const validValues = [
            'on', 'off', 'name', 'honorific-prefix', 'given-name', 'additional-name',
            'family-name', 'honorific-suffix', 'nickname', 'email', 'username',
            'new-password', 'current-password', 'one-time-code', 'organization-title',
            'organization', 'street-address', 'address-line1', 'address-line2',
            'address-line3', 'address-level4', 'address-level3', 'address-level2',
            'address-level1', 'country', 'country-name', 'postal-code', 'cc-name',
            'cc-given-name', 'cc-additional-name', 'cc-family-name', 'cc-number',
            'cc-exp', 'cc-exp-month', 'cc-exp-year', 'cc-csc', 'cc-type',
            'transaction-currency', 'transaction-amount', 'language', 'bday',
            'bday-day', 'bday-month', 'bday-year', 'sex', 'tel', 'tel-country-code',
            'tel-national', 'tel-area-code', 'tel-local', 'tel-extension', 'impp',
            'url', 'photo'
        ];

        const values = autocomplete.split(/\s+/);
        for (let i = 0; i < values.length; i++) {
            // Simple check: if any token is not in the list (and not a section-* token), fail.
            const val = values[i];
            if (val.startsWith('section-')) continue;
            if (!validValues.includes(val)) {
                return false;
            }
        }

        return true;
    }
});

module.exports = [autocompleteValidCheck];
