const check = {
    id: 'aria-allowed-attr',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'ARIA attributes are correct for the role',
            fail: 'One or more ARIA attributes are not allowed for this role. Check the ARIA spec for valid attributes.'
        }
    },
    evaluate: function (node, options) {
        const { globalAttributes, roles, validAttributes } = require('../../utils/aria-definitions');
        const { getRole } = require('../../utils/aria-utils');

        const role = getRole(node);
        if (!role) return { pass: true };

        if (!roles[role]) {
            return { pass: true };
        }

        const allowed = roles[role].allowed || [];
        const required = roles[role].required || [];
        const whitelist = [...allowed, ...required, ...globalAttributes];

        const invalidAttrs = [];
        const attrs = node.attributes;
        for (let i = 0; i < attrs.length; i++) {
            const attrName = attrs[i].name;
            if (attrName.startsWith('aria-')) {
                if (!whitelist.includes(attrName)) {
                    if (validAttributes.includes(attrName)) {
                        invalidAttrs.push(attrName);
                    }
                }
            }
        }

        if (invalidAttrs.length > 0) {
            return {
                pass: false,
                message: `Attributes not allowed for role "${role}": ${invalidAttrs.join(', ')}`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
