
const check = {
    id: 'color-contrast',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Text has sufficient contrast',
            fail: 'Text contrast is below the required ratio',
            incomplete: 'Could not determine contrast ratio'
        }
    },
    selector: '*',
    evaluate: function (node) {
        // Skip non-element nodes
        if (node.nodeType !== 1) return { pass: true };

        const win = node.ownerDocument.defaultView;
        if (!win) return { pass: true };

        const style = win.getComputedStyle(node);


        // --- 1. Advanced Visibility Check ---
        // Check standard display/visibility
        if (style.display === 'none' || style.visibility === 'hidden' || parseFloat(style.opacity) === 0) {
            return { pass: true };
        }

        // Check for 1px clipping (SR-only pattern)
        // e.g. clip: rect(0 0 0 0), width: 1px, height: 1px, overflow: hidden
        if (style.position === 'absolute' || style.position === 'fixed') {
            // Basic size check
            const width = parseFloat(style.width);
            const height = parseFloat(style.height);

            if (width <= 1 && height <= 1 && style.overflow === 'hidden') {
                return { pass: true };
            }
            if (style.clip === 'rect(0px, 0px, 0px, 0px)' || style.clip === 'rect(0 0 0 0)') {
                return { pass: true };
            }
        }
        // Basic clip-path check
        if (style.clipPath === 'inset(100%)' || style.clipPath === 'circle(0% at 50% 50%)') {
            return { pass: true };
        }


        // --- Color Parsing & Helpers ---
        function parseColor(c) {
            if (!c) return null;
            c = c.trim().toLowerCase();
            if (c === 'transparent' || c === 'none') return { r: 0, g: 0, b: 0, a: 0 };

            // Import color map
            const cssColors = require('./color-keywords.js');
            if (cssColors[c]) {
                const [r, g, b] = cssColors[c];
                return { r, g, b, a: 1 };
            }

            if (c.startsWith('#')) {
                if (c.length === 4) {
                    return {
                        r: parseInt(c[1] + c[1], 16),
                        g: parseInt(c[2] + c[2], 16),
                        b: parseInt(c[3] + c[3], 16),
                        a: 1
                    };
                } else if (c.length === 7) {
                    return {
                        r: parseInt(c.slice(1, 3), 16),
                        g: parseInt(c.slice(3, 5), 16),
                        b: parseInt(c.slice(5, 7), 16),
                        a: 1
                    };
                }
            }

            const rgbMatch = c.match(/^rgba?\((\d+),\s*(\d+),\s*(\d+)(?:,\s*([\d.]+))?\)$/);
            if (rgbMatch) {
                return {
                    r: parseInt(rgbMatch[1]),
                    g: parseInt(rgbMatch[2]),
                    b: parseInt(rgbMatch[3]),
                    a: rgbMatch[4] !== undefined ? parseFloat(rgbMatch[4]) : 1
                };
            }
            return null;
        }

        function getColorName(r, g, b) {
            const cssColors = require('./color-keywords.js');
            let minDistance = Infinity;
            let nearestColor = "unknown";
            const target = [r, g, b];

            for (const [name, rgb] of Object.entries(cssColors)) {
                const d = Math.pow(target[0] - rgb[0], 2) + Math.pow(target[1] - rgb[1], 2) + Math.pow(target[2] - rgb[2], 2);
                if (d < minDistance) {
                    minDistance = d;
                    nearestColor = name;
                    if (d === 0) return name.charAt(0).toUpperCase() + name.slice(1);
                }
            }
            return nearestColor.charAt(0).toUpperCase() + nearestColor.slice(1);
        }

        function getLum(c) {
            const RsRGB = c.r / 255;
            const GsRGB = c.g / 255;
            const BsRGB = c.b / 255;
            const R = (RsRGB <= 0.03928) ? RsRGB / 12.92 : Math.pow((RsRGB + 0.055) / 1.055, 2.4);
            const G = (GsRGB <= 0.03928) ? GsRGB / 12.92 : Math.pow((GsRGB + 0.055) / 1.055, 2.4);
            const B = (BsRGB <= 0.03928) ? BsRGB / 12.92 : Math.pow((BsRGB + 0.055) / 1.055, 2.4);
            return 0.2126 * R + 0.7152 * G + 0.0722 * B;
        }

        function getContrast(c1, c2) {
            const l1 = getLum(c1);
            const l2 = getLum(c2);
            return (Math.max(l1, l2) + 0.05) / (Math.min(l1, l2) + 0.05);
        }

        // Helper to mix two colors (fg over bg)
        function mixColors(fg, bg) {
            // Normal alpha blending: out = fg.a * fg + (1 - fg.a) * bg
            // Result alpha = fg.a + bg.a * (1 - fg.a)
            const a = fg.a + bg.a * (1 - fg.a);
            if (a === 0) return { r: 0, g: 0, b: 0, a: 0 };

            return {
                r: (fg.r * fg.a + bg.r * bg.a * (1 - fg.a)) / a,
                g: (fg.g * fg.a + bg.g * bg.a * (1 - fg.a)) / a,
                b: (fg.b * fg.a + bg.b * bg.a * (1 - fg.a)) / a,
                a: a
            };
        }

        function resolveEffectiveColors(el, styleObj) {
            // 1. Try Visual Stack (Browser/Puppeteer)
            // This is best for absolute positioning etc, but JSDOM lacks it.
            if (win.document.elementsFromPoint && typeof win.document.elementsFromPoint === 'function') {
                const rect = el.getBoundingClientRect();
                const x = rect.left + rect.width / 2;
                const y = rect.top + rect.height / 2;
                const stack = win.document.elementsFromPoint(x, y);

                if (stack && stack.length > 0) {
                    // We need two things:
                    // 1. Effective Background (behind text)
                    // 2. Effective Foreground (text color blended with opacity/layers)

                    // Visual stack is Front -> Back.
                    // stack[0] is usually the element or a child.
                    // To find BG: Iterate stack. Find first opaque pixel BEHIND the text layer.
                    // To find FG: Text is usually on stack[0].

                    // BUT, elementsFromPoint opaque-check is hard because we don't know opacities of stack items easily without traversing.
                    // So we might stick to DOM strategy if we want opacity support purely.
                    // OR we can use the `elementsFromPoint` just to identify the LAYERS, then compute their visual contribution.

                    // For now, let's prioritize the DOM Opacity Fix (User's BBC issue), 
                    // but keep visual stack for finding 'which element provides background'.

                    // If we are in JSDOM, this block is skipped anyway.
                }
            }

            // 2. DOM Traversal (Opacity Aware)
            // We need to resolve TWO colors:
            // A. The text color (FG) mixed with all parents up to root.
            // B. The background color (BG) mixed with all parents up to root.

            // Path: [El, Parent, ..., Root]
            const path = [];
            let curr = el;
            while (curr) {
                if (curr.nodeType === 1) path.push(curr);

                if (curr.parentElement) {
                    curr = curr.parentElement;
                } else {
                    const root = curr.getRootNode ? curr.getRootNode() : null;
                    if (root && root.nodeType === 11 && root.host) {
                        curr = root.host;
                    } else {
                        break;
                    }
                }
            }

            const baseWhite = { r: 255, g: 255, b: 255, a: 1 };

            // Calculate Effective Foreground
            let fgCurrent = parseColor(styleObj ? styleObj.color : win.getComputedStyle(el).color) || { r: 0, g: 0, b: 0, a: 1 };

            // Calculate Effective Background
            // Initial BG is transparent (unless el has bg)
            // We start 'under' the text. So El's BG is the first layer.
            let bgCurrent = parseColor(styleObj ? styleObj.backgroundColor : win.getComputedStyle(el).backgroundColor) || { r: 0, g: 0, b: 0, a: 0 };

            // Check for background image on element itself
            let style = styleObj || win.getComputedStyle(el);
            if (style.backgroundImage && style.backgroundImage !== 'none' && (style.backgroundImage.includes('url(') || style.backgroundImage.includes('gradient'))) {
                return { bg: { isComplex: true }, fg: fgCurrent };
            }

            // Iterate UP the tree (Bubbling up composition)
            // Formula: NewColor = (CurrentColor OVER NodeBG) * NodeOpacity

            for (let i = 0; i < path.length; i++) {
                const node = path[i];
                const compStyle = (i === 0 && styleObj) ? styleObj : win.getComputedStyle(node);

                const opacity = parseFloat(compStyle.opacity);
                const validOpacity = isNaN(opacity) ? 1 : opacity;

                // Background of this node
                // For el (i=0), we already took its color/bg. But iterating allows uniform logic?
                // Wait. Text is ON TOP of El.BG.
                // So FG Loop: Mix(FG, El.BG). Then Apply El.Opacity.
                // BG Loop: Mix(Transp, El.BG). Then Apply El.Opacity.

                // Let's refine.
                const nodeBg = parseColor(compStyle.backgroundColor) || { r: 0, g: 0, b: 0, a: 0 };

                if (compStyle.backgroundImage && compStyle.backgroundImage !== 'none' && (compStyle.backgroundImage.includes('url(') || compStyle.backgroundImage.includes('gradient'))) {
                    // If any parent has a background image, we might consider the BG complex/unknown
                    // Unless it is fully occluded? Conservative: return complex.
                    return { bg: { isComplex: true }, fg: fgCurrent };
                }

                if (i === 0) {
                    // Initial step: Mix Text over ElementBG
                    fgCurrent = mixColors(fgCurrent, nodeBg);
                    // BG is just ElementBG (mixed over transparent)
                    bgCurrent = nodeBg; // mixColors(t, nodeBg) == nodeBg
                } else {
                    // Parent Node
                    // Mix Current over ParentBG
                    fgCurrent = mixColors(fgCurrent, nodeBg);
                    bgCurrent = mixColors(bgCurrent, nodeBg);
                }

                // Apply Opacity to both layers
                fgCurrent.a *= validOpacity;
                bgCurrent.a *= validOpacity;
            }

            // Finally mix over Base White (Root assumption)
            fgCurrent = mixColors(fgCurrent, baseWhite);
            bgCurrent = mixColors(bgCurrent, baseWhite);

            return { fg: fgCurrent, bg: bgCurrent };
        }

        function rgbToHex(r, g, b) {
            return "#" + [r, g, b].map(x => {
                const hex = Math.round(x).toString(16);
                return hex.length === 1 ? '0' + hex : hex;
            }).join('');
        }

        // --- Core Evaluation Logic ---
        const results = [];

        function evaluateContrast(targetNode, targetStyle, label) {
            // Determine Context (SVG vs HTML)
            const isSVG = targetNode.namespaceURI === 'http://www.w3.org/2000/svg';
            let fgProp = isSVG ? (targetStyle.fill || targetStyle.color) : targetStyle.color;

            if (isSVG && targetStyle.fill === 'currentColor') fgProp = targetStyle.color;

            const fgRaw = parseColor(fgProp);
            if (!fgRaw) return;

            // --- Text Shadow Check ---
            if (targetStyle.textShadow && targetStyle.textShadow !== 'none') {
                const matches = targetStyle.textShadow.match(/(rgba?\([^)]+\)|hsla?\([^)]+\)|#[0-9a-fA-F]+|[a-z]+)/gi);
                let shadowColor = null;
                if (matches) {
                    for (const m of matches) {
                        const parsed = parseColor(m);
                        if (parsed) {
                            shadowColor = parsed;
                            break;
                        }
                    }
                }

                if (shadowColor && shadowColor.a > 0.5) {
                    const shadowContrast = getContrast(fgRaw, shadowColor);

                    let fontSizeFn = targetStyle.fontSize;
                    let isBold = targetStyle.fontWeight === 'bold' || parseInt(targetStyle.fontWeight) >= 700;
                    let sizePx = 16;
                    if (fontSizeFn.endsWith('px')) sizePx = parseFloat(fontSizeFn);

                    const isLarge = (sizePx >= 24) || (sizePx >= 18.66 && isBold);
                    const requiredRatio = isLarge ? 3.0 : 4.5;

                    if (shadowContrast >= requiredRatio) return;
                }
            }

            // --- Resolve Effective Colors (Opacity Aware) ---
            const visualResult = resolveEffectiveColors(targetNode, targetStyle);
            const fgColor = visualResult.fg;
            const bgColor = visualResult.bg;

            if (bgColor.isComplex) {
                results.push({
                    pass: false,
                    incomplete: true,
                    node: targetNode,
                    message: `${label}: Unable to determine contrast due to background image or gradient`,
                    data: { confidence: 'low', actId: 'afw4f7' }
                });
                return;
            }

            const contrast = getContrast(fgColor, bgColor);

            // Determine required ratio
            let fontSizeFn = targetStyle.fontSize;
            let isBold = targetStyle.fontWeight === 'bold' || parseInt(targetStyle.fontWeight) >= 700;
            let sizePx = 16;

            if (fontSizeFn.endsWith('px')) {
                sizePx = parseFloat(fontSizeFn);
            } else if (fontSizeFn.endsWith('pt')) {
                sizePx = parseFloat(fontSizeFn) * 1.333;
            } else if (fontSizeFn.endsWith('em') || fontSizeFn.endsWith('rem')) {
                sizePx = parseFloat(fontSizeFn) * 16;
            }

            // WCAG Large text: 18.66px (14pt) bold or 24px (18pt) normal
            const isLarge = (sizePx >= 24) || (sizePx >= 18.66 && isBold);
            const requiredRatio = isLarge ? 3.0 : 4.5;

            if (contrast < requiredRatio) {
                const pts = (sizePx * 0.75).toFixed(1);
                const weight = isBold ? 'bold' : targetStyle.fontWeight;

                const fgName = getColorName(fgColor.r, fgColor.g, fgColor.b);
                const bgName = getColorName(Math.round(bgColor.r), Math.round(bgColor.g), Math.round(bgColor.b));
                const fgHex = rgbToHex(fgColor.r, fgColor.g, fgColor.b);
                const bgHex = rgbToHex(bgColor.r, bgColor.g, bgColor.b);

                results.push({
                    pass: false,
                    message: `${label}: Insufficient color contrast of ${contrast.toFixed(2)} (foreground color: ${fgHex} rgb(${fgColor.r}, ${fgColor.g}, ${fgColor.b}) (${fgName}), background color: ${bgHex} rgb(${Math.round(bgColor.r)}, ${Math.round(bgColor.g)}, ${Math.round(bgColor.b)}) (${bgName}), font size: ${pts}pt (${sizePx}px), font weight: ${weight}). Expected contrast ratio of ${requiredRatio}:1`,
                    data: {
                        confidence: 'high',
                        actId: 'afw4f7',
                        contrastRatio: contrast,
                        requiredRatio: requiredRatio,
                        fontSize: sizePx,
                        fontWeight: weight
                    }
                });
            } else {
                // Explicit pass result for better data granularity if needed, 
                // but typically we just don't push to failures.
                // However, for debugging we might want "passed" checks to have data too?
                // The runner usually handles "pass" if no failures. 
                // But let's verify if we need to return specific success data.
                // The current architecture returns { pass: true } at the end if no failures.
            }
        }


        // --- Execution ---

        // 1. Main Element
        // Determine if it has text or is an input OR is SVG TEXT
        const tagName = node.tagName.toLowerCase();
        let hasContent = false;

        if (tagName === 'img' || tagName === 'svg') return { pass: true };

        if (tagName === 'text' || tagName === 'tspan') {
            // SVG Text
            if (node.textContent.trim().length > 0) hasContent = true;
        } else {
            // HTML check
            hasContent = Array.from(node.childNodes).some(child =>
                child.nodeType === 3 && child.textContent.trim().length > 0
            );
        }

        const isInput = ['input', 'textarea', 'select', 'button'].includes(tagName);

        if (hasContent || isInput) {
            evaluateContrast(node, style, `Element <${tagName}>`);
        }

        // 2. Check Pseudo-elements (Only for HTML elements generally)
        if (node.namespaceURI !== 'http://www.w3.org/2000/svg') {
            const beforeStyle = win.getComputedStyle(node, '::before');
            const beforeContent = beforeStyle.content;
            if (beforeContent && beforeContent !== 'none' && beforeContent !== '""') {
                evaluateContrast(node, beforeStyle, 'Pseudo-element ::before');
            }

            const afterStyle = win.getComputedStyle(node, '::after');
            const afterContent = afterStyle.content;
            if (afterContent && afterContent !== 'none' && afterContent !== '""') {
                evaluateContrast(node, afterStyle, 'Pseudo-element ::after');
            }
        }

        // --- Result Aggregation ---
        if (results.length === 0) return { pass: true };

        const failures = results.filter(r => !r.incomplete);
        const incompletes = results.filter(r => r.incomplete);

        if (failures.length > 0) {
            return {
                pass: false,
                message: failures.map(f => f.message).join(' | '),
                data: failures[0].data
            };
        } else if (incompletes.length > 0) {
            return {
                pass: false,
                incomplete: true,
                message: incompletes.map(i => i.message).join(' | '),
                data: incompletes[0].data
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
