const dom = require('../../utils/dom');

const check = {
    id: 'table-fake-caption',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Table uses caption element or has no caption-like cell',
            fail: 'Table uses a cell as a caption instead of the <caption> element'
        }
    },
    selector: 'table',
    evaluate: function (node) {
        // If table is presentation, skip
        if (node.getAttribute('role') === 'presentation' || node.getAttribute('role') === 'none') return { pass: true };

        // If table has a real caption, we assume it's fine (or at least it HAS a caption).
        // Check for <caption> child
        const caption = node.querySelector('caption');
        if (caption) return { pass: true };

        // Check first row
        const rows = node.querySelectorAll('tr');
        if (rows.length === 0) return { pass: true };

        const firstRow = rows[0];
        const cells = firstRow.querySelectorAll('td, th');

        // If first row has exactly ONE cell
        if (cells.length === 1) {
            const cell = cells[0];
            // Check if it contains text
            const text = cell.innerText || cell.textContent || '';
            if (text.trim().length > 0) {
                // It's a single cell in the first row with text.
                // It might be a fake caption.
                // Usually, real headers have multiple cells or don't span the ENTIRE table if there are multiple columns.
                // But we don't know total columns easily without counting next row.

                // Check if next row exists and has > 1 cell.
                if (rows.length > 1) {
                    const secondRowCells = rows[1].querySelectorAll('td, th');
                    if (secondRowCells.length > 1) {
                        // First row is 1 cell, second row is > 1 cell.
                        // This strongly implies the first row is being used as a caption/header for the whole table.
                        return {
                            pass: false,
                            message: 'Table uses a cell as a caption. Screen readers might not associate it correctly with the table. Use the `<caption>` element for table titles.'
                        };
                    }
                }
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
