/**
 * Checks for html-lang-valid
 */
const Check = require('../../core/check');

const htmlLangValid = new Check({
    id: 'html-lang-valid',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'The <html> element has a valid lang attribute',
            fail: 'The `lang` attribute on `<html>` is invalid. Screen readers use this to select the correct pronunciation. Ensure the value matches a valid BCP 47 language code (e.g., "en", "fr-CA").'
        }
    },
    evaluate: function (node) {
        if (!node.hasAttribute('lang')) return true; // Handled by html-has-lang
        const lang = node.getAttribute('lang');
        const validIso6391 = [
            'ab', 'aa', 'af', 'ak', 'sq', 'am', 'ar', 'an', 'hy', 'as', 'av', 'ae', 'ay', 'az',
            'bm', 'ba', 'eu', 'be', 'bn', 'bh', 'bi', 'bs', 'br', 'bg', 'my', 'ca', 'ch', 'ce',
            'ny', 'zh', 'cv', 'kw', 'co', 'cr', 'hr', 'cs', 'da', 'dv', 'nl', 'dz', 'en', 'eo',
            'et', 'ee', 'fo', 'fj', 'fi', 'fr', 'ff', 'gl', 'ka', 'de', 'el', 'gn', 'gu', 'ht',
            'ha', 'he', 'hz', 'hi', 'ho', 'hu', 'ia', 'id', 'ie', 'ga', 'ig', 'ik', 'io', 'is',
            'it', 'iu', 'ja', 'jv', 'kl', 'kn', 'kr', 'ks', 'kk', 'km', 'ki', 'rw', 'ky', 'kv',
            'kg', 'ko', 'ku', 'kj', 'la', 'lb', 'lg', 'li', 'ln', 'lo', 'lt', 'lu', 'lv', 'gv',
            'mk', 'mg', 'ms', 'ml', 'mt', 'mi', 'mr', 'mh', 'mn', 'na', 'nv', 'nd', 'ne', 'ng',
            'nb', 'nn', 'no', 'ii', 'nr', 'oc', 'oj', 'cu', 'om', 'or', 'os', 'pa', 'pi', 'fa',
            'pl', 'ps', 'pt', 'qu', 'rm', 'rn', 'ro', 'ru', 'sa', 'sc', 'sd', 'se', 'sm', 'sg',
            'sr', 'gd', 'sn', 'si', 'sk', 'sl', 'so', 'st', 'es', 'su', 'sw', 'ss', 'sv', 'ta',
            'te', 'tg', 'th', 'ti', 'bo', 'tk', 'tl', 'tn', 'to', 'tr', 'ts', 'tt', 'tw', 'ty',
            'ug', 'uk', 'ur', 'uz', 've', 'vi', 'vo', 'wa', 'cy', 'wo', 'fy', 'xh', 'yi', 'yo',
            'za', 'zu'
        ];

        const parts = lang.split('-');
        const primary = parts[0].toLowerCase();

        if (!validIso6391.includes(primary)) {
            return false;
        }

        // Simple regex for BCP 47 structure
        const bcp47Regex = /^[a-zA-Z]{2,3}(-[a-zA-Z0-9]{2,8})*$/;
        return bcp47Regex.test(lang);
    }
});

module.exports = [htmlLangValid];
