/**
 * Checks for definition-list
 */
const Check = require('../../core/check');

const definitionList = new Check({
    id: 'definition-list',
    metadata: {
        messages: {
            pass: 'Definition list has valid children',
            fail: 'Definition list contains invalid children. Screen readers might not navigate the list correctly. Only use `<dt>`, `<dd>`, `<div>`, `<script>` or `<template>` elements inside `<dl>`.'
        }
    },
    evaluate: function (node) {
        // Check all direct children
        const children = Array.from(node.children);
        const validTags = ['DT', 'DD', 'DIV', 'SCRIPT', 'TEMPLATE'];

        for (const child of children) {
            if (!validTags.includes(child.tagName)) {
                return false;
            }
        }
        return true;
    }
});

module.exports = [definitionList];
