const RuleManager = require('./rule-manager');
const PluginManager = require('./plugin-manager');
const CheckManager = require('./check-manager');
const Runner = require('./runner');
const logger = require('../logger');

class Engine {
    constructor() {
        this.ruleManager = new RuleManager();
        this.checkManager = new CheckManager();
        this.pluginManager = new PluginManager(this);
        this.configuration = {
            rules: [],
            checks: [],
            disableOtherRules: false,
            screenshotProvider: null
        };
    }

    /**
     * Configure the engine
     * @param {Object} configuration 
     */
    configure(configuration) {
        this.configuration = {
            ...this.configuration,
            ...configuration
        };

        // Handle Presets
        if (configuration.preset) {
            const presets = require('../config/presets');
            const presetConfig = presets[configuration.preset];

            if (presetConfig) {
                // If a preset is selected, we need to decide strategy:
                // 1. Disable all rules first? Or just enable matching?
                // Typically users want ONLY the preset rules.

                const allRules = this.ruleManager.getRules();

                // First, determine the set of tags allowed
                const allowedTags = presetConfig.tags || [];

                allRules.forEach(rule => {
                    // Check if rule has any of the allowed tags
                    const hasTag = rule.tags && rule.tags.some(tag => allowedTags.includes(tag));
                    rule.enabled = hasTag;
                });
            } else {
                logger.warn(`Preset '${configuration.preset}' not found.`);
            }
        }

        // Apply specific rule overrides AFTER preset
        if (configuration.rules) {
            configuration.rules.forEach(ruleConfig => {
                const rule = this.ruleManager.getRule(ruleConfig.id);
                if (rule) {
                    if (ruleConfig.enabled !== undefined) {
                        rule.enabled = ruleConfig.enabled;
                    }
                }
            });
        }
    }

    /**
     * Reset the engine configuration
     */
    reset() {
        this.configuration = {
            rules: [],
            checks: [],
            disableOtherRules: false
        };
        // Reset rules to default state if needed (requires storing default state)
        // For now, we'll just keep registered rules but reset config
    }

    /**
     * Register a new rule
     * @param {Object} ruleConfig 
     */
    addRule(ruleConfig) {
        this.ruleManager.addRule(ruleConfig);
        if (ruleConfig.checks) {
            this.addCheck(ruleConfig.checks);
        }
    }

    /**
     * Register a new check
     * @param {Object} checkConfig 
     */
    addCheck(checkConfig) {
        if (Array.isArray(checkConfig)) {
            checkConfig.forEach(c => this.checkManager.addCheck(c));
        } else {
            this.checkManager.addCheck(checkConfig);
        }
    }

    /**
     * Register a plugin
     * @param {Object} plugin 
     */
    registerPlugin(plugin) {
        this.pluginManager.register(plugin);
    }

    /**
     * Run the engine
     * @param {Element|String} context 
     * @param {Object} options 
     * @param {Function} callback 
     * @returns {Promise<Object>}
     */
    async run(context, options, callback) {
        logger.info('Satya Engine: Starting scan...');
        logger.debug('Engine starting run', { context, options });
        const runner = new Runner(this.ruleManager, this.checkManager, this.configuration);
        return runner.run(context, options, callback);
    }

    get rules() {
        return this.ruleManager.getRules();
    }
}

module.exports = Engine;
