/**
 * Checks for html-has-lang
 */
const Check = require('../../core/check');

const hasLang = new Check({
    id: 'has-lang',
    metadata: {
        messages: {
            pass: 'The <html> element has a lang attribute',
            fail: 'The `<html>` element is missing a `lang` attribute. Screen readers assume the default language, which might be incorrect. Add `lang="en"` (or appropriate code) to the `<html>` tag.'
        }
    },
    evaluate: function (node) {
        return node.hasAttribute('lang') && node.getAttribute('lang').trim().length > 0;
    }
});

module.exports = [hasLang];
