const check = {
    id: 'server-side-image-map',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'No server-side image map used',
            fail: 'Server-side image map detected. These are inaccessible to keyboard and screen reader users. Use client-side image maps with `<area>` elements instead.'
        }
    },
    evaluate: function (node, options) {
        if (node.hasAttribute('ismap')) {
            // Technically allowed if there are text links, but generally best avoided.
            // Simplified check: fail if ismap is present.
            return { pass: false };
        }
        return { pass: true };
    }
};

module.exports = [check];
