const Check = require('../../core/check');

const svgAriaLabelCheck = new Check({
    id: 'svg-aria-label-check',
    metadata: {
        messages: {
            pass: 'SVG element has an accessible name',
            fail: 'SVG element is missing an accessible name. Screen readers cannot describe this graphic. Add `aria-label`, `aria-labelledby`, or a `<title>` element.'
        }
    },
    evaluate: function (ele) {
        // Check aria-label
        if (ele.hasAttribute('aria-label')) {
            const label = ele.getAttribute('aria-label');
            if (label && label.trim().length > 0) {
                return true;
            }
        }

        // Check aria-labelledby
        if (ele.hasAttribute('aria-labelledby')) {
            const labelledBy = ele.getAttribute('aria-labelledby');
            if (labelledBy && labelledBy.trim().length > 0) {
                return true;
            }
        }

        // Check title element
        const title = ele.querySelector('title');
        if (title && title.textContent.trim().length > 0) {
            return true;
        }

        return false;
    }
});

module.exports = [svgAriaLabelCheck];
