const check = {
    id: 'table-duplicate-name',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'Table summary and caption are distinct',
            fail: 'Table summary and caption are identical. This creates redundant information for screen reader users. Ensure `summary` and `<caption>` provide distinct information or remove the summary.'
        }
    },
    evaluate: function (node, options) {
        const summary = node.getAttribute('summary');
        const caption = node.querySelector('caption');

        if (summary && caption && caption.textContent) {
            if (summary.trim() === caption.textContent.trim()) {
                return { pass: false, message: 'Summary and caption are identical' };
            }
        }
        return { pass: true };
    }
};

module.exports = [check];
