/**
 * Enhanced Selector System
 */

const dom = require('./dom');

const Selector = {
    /**
     * Check if a node matches a selector
     * @param {HTMLElement} node 
     * @param {string|string[]} selector 
     * @returns {boolean}
     */
    matches: (node, selector) => {
        if (!node) return false;

        // Array means OR
        if (Array.isArray(selector)) {
            return selector.some(s => Selector.matches(node, s));
        }

        // Pseudo-selectors
        if (selector === ':visible') return dom.isVisible(node);
        if (selector === ':focusable') return isFocusable(node);

        // Virtual selectors (Roles)
        if (selector.startsWith('role:')) {
            const role = selector.split(':')[1];
            return node.getAttribute('role') === role; // Simplified, needs full role resolution
        }

        // Standard selector
        try {
            return node.matches(selector);
        } catch (e) {
            console.warn(`Invalid selector: ${selector}`);
            return false;
        }
    }
};

function isFocusable(element) {
    if (!dom.isVisible(element)) return false;
    const nodeName = element.nodeName.toLowerCase();
    if (['a', 'area'].includes(nodeName) && element.hasAttribute('href')) return true;
    if (['input', 'select', 'textarea', 'button'].includes(nodeName) && !element.disabled) return true;
    if (element.hasAttribute('tabindex')) return true;
    return false;
}

module.exports = Selector;
