const dom = require('../../utils/dom');

const check = {
    id: 'aria-meter-name',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'ARIA meter has an accessible name',
            fail: 'Meter is missing an accessible name. Users rely on the name to understand what the meter measures. Add `aria-label` or `aria-labelledby`.'
        }
    },
    evaluate: function (node, options) {
        const name = dom.computeAccessibleName(node);
        return {
            pass: !!(name && name.trim().length > 0)
        };
    }
};

module.exports = [check];
