const Check = require('../../core/check');

const linkTargetBlankSecurityCheck = new Check({
    id: 'link-target-blank-security-check',
    metadata: {
        messages: {
            pass: 'Link with target="_blank" has rel="noopener" or rel="noreferrer"',
            fail: 'Unsafe `target="_blank"`. Opening new tabs without protections exposes users to security risks. Add `rel="noopener noreferrer"` to the link.'
        }
    },
    evaluate: function (ele) {
        if (ele.hasAttribute('target') && ele.getAttribute('target') === '_blank') {
            const rel = ele.getAttribute('rel');
            if (!rel) {
                return false;
            }
            const relValues = rel.toLowerCase().split(/\s+/);
            if (relValues.includes('noopener') || relValues.includes('noreferrer')) {
                return true;
            }
            return false;
        }
        return true;
    }
});

module.exports = [linkTargetBlankSecurityCheck];
