/**
 * Checks for empty-heading
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasContent = new Check({
    id: 'heading-has-content',
    metadata: {
        messages: {
            pass: 'Heading has accessible text',
            fail: 'Heading is empty. Screen reader users cannot understand the structure of the page. Add text content or remove the empty heading tag.'
        }
    },
    evaluate: function (node) {
        return !!dom.computeAccessibleName(node);
    }
});

const isHidden = new Check({
    id: 'is-hidden',
    metadata: {
        messages: {
            pass: 'Element is hidden',
            fail: 'Heading is visible but empty. This creates a confusing navigation stop for screen readers. Add text or hide the element.'
        }
    },
    evaluate: function (node) {
        return !dom.isVisible(node);
    }
});

module.exports = [hasContent, isHidden];
