const check = {
    id: 'aria-braille-label',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'aria-braille-label has a value',
            fail: 'Empty `aria-braille-label`. Braille users will receive no information. Provide a valid text string for the braille label.'
        }
    },
    selector: '[aria-braille-label]',
    evaluate: function (node) {
        const val = node.getAttribute('aria-braille-label');
        // Basic check: must strictly be non-empty/whitespace?
        // Axe checks "aria-braille-label-name" check which ensures it's not empty.

        if (!val || val.trim().length === 0) {
            return {
                pass: false,
                message: 'aria-braille-label attribute must not be empty'
            };
        }
        return { pass: true };
    }
};

module.exports = [check];
