/**
 * Checks for td-headers-attr
 */
const Check = require('../../core/check');

const tdHeadersAttrCheck = new Check({
    id: 'td-headers-attr',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'The headers attribute uses valid IDs',
            fail: 'The `headers` attribute references invalid or missing IDs. Screen readers use this attribute to associate cells with headers. Ensure all IDs exist in the same table.'
        }
    },
    evaluate: function (node) {
        if (!node.hasAttribute('headers')) return true;

        const headers = node.getAttribute('headers').split(/\s+/);
        // Find the table context
        const table = node.closest('table');
        if (!table) return false; // orphan td?

        for (const id of headers) {
            if (!id) continue;
            const headerCell = table.querySelector(`th#${id}`);
            if (!headerCell) return false;
        }
        return true;
    }
});

module.exports = [tdHeadersAttrCheck];
