const check = {
    id: 'landmark-one-main',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Page has exactly one main landmark',
            fail: 'Page must have exactly one main landmark. Users rely on a unique `main` region to jump to the primary content.'
        }
    },
    evaluate: function (node, options) {
        // Run only once per page (on the root element usually)
        if (node.tagName !== 'HTML' && node.parentElement) return { pass: true };

        const mains = document.querySelectorAll('main, [role="main"]');
        if (mains.length === 0) {
            return {
                pass: false,
                message: 'No main landmark found. Users rely on a `main` region to jump to content. Add a `<main>` element or `role="main"` to the primary content container.'
            };
        }
        if (mains.length > 1) {
            return {
                pass: false,
                message: 'Multiple main landmarks detected. Users rely on a unique `main` region to jump to the primary content. Ensure only one `main` or `role="main"` exists.'
            };
        }
        return { pass: true };
    }
};

module.exports = [check];
