const Check = require('../../core/check');

const metaRefreshCheck = new Check({
    id: 'meta-refresh-check',
    metadata: {
        messages: {

            fail: 'Meta refresh delay is under 20 hours. Users who cannot read or react quickly enough are disoriented by unexpected page reloads. Remove the `http-equiv="refresh"` attribute or extend the delay.'
        }
    },
    evaluate: function (node) {
        const content = node.getAttribute('content');
        if (!content) return true;

        // Split "5; url=..."
        const parts = content.split(';');
        const delay = parseFloat(parts[0]);

        if (isNaN(delay)) return true; // Let invalid values pass (handled by other validation rules if any)

        // Strict: fail if delay > 0 and < 72000
        if (delay > 0 && delay < 72000) {
            return false;
        }
        return true;
    }
});

module.exports = [metaRefreshCheck];
