const check = {
    id: 'aria-roles',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Role attribute has a valid value',
            fail: 'Role attribute contains invalid value(s). Screen readers will ignore invalid roles. Ensure role values match the WAI-ARIA specification.'
        }
    },
    evaluate: function (node, options) {
        const { validRoles } = require('../../utils/aria-definitions');
        const roleStr = node.getAttribute('role');

        if (!roleStr) return { pass: true };

        const rolesToCheck = roleStr.split(/\s+/).filter(Boolean);
        const invalid = [];

        for (const role of rolesToCheck) {
            if (!validRoles.includes(role)) {
                invalid.push(role);
            }
        }

        if (invalid.length > 0) {
            return {
                pass: false,
                message: `Invalid roles: ${invalid.join(', ')}`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
