const Check = require('../../core/check');

const noAutoplayMediaCheck = new Check({
    id: 'no-autoplay-media-check',
    metadata: {
        messages: {
            pass: 'Media element does not autoplay',
            fail: 'Media element autoplays. Unexpected sounds or movement disrupt users. Remove the `autoplay` attribute.'
        }
    },
    evaluate: function (ele) {
        // Check if autoplay attribute is present
        if (ele.hasAttribute('autoplay')) {
            return false;
        }
        return true;
    }
});

module.exports = [noAutoplayMediaCheck];
