const check = {
    id: 'nested-interactive',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Interactive element is not nested inside another interactive element',
            fail: 'Interactive element must not be nested inside another interactive element'
        }
    },
    evaluate: function (node, options) {
        // Check ancestry for interactive elements
        // Interactive elements: a[href], button, input, select, textarea, [tabindex], [role="button/link..."]
        // The selector picks up interactive elements. We just check if they have an interactive parent.

        const interactiveRoles = ['button', 'link', 'checkbox', 'menuitem', 'menuitemcheckbox', 'menuitemradio', 'option', 'radio', 'searchbox', 'switch', 'tab', 'textbox', 'treeitem'];
        const interactiveTags = ['a', 'button', 'input', 'select', 'textarea', 'details', 'embed', 'iframe', 'label', 'audio', 'video'];
        // Note: 'a' is only interactive if it has href, which the selector should handle or we check here.

        let current = node.parentElement;
        while (current && current.tagName !== 'BODY') {
            const tag = current.tagName.toLowerCase();
            const role = current.getAttribute('role');
            const tabindex = current.getAttribute('tabindex');

            let isInteractive = false;
            if (interactiveTags.includes(tag)) {
                if (tag === 'a' && !current.hasAttribute('href')) isInteractive = false;
                else isInteractive = true;
            }
            if (interactiveRoles.includes(role)) isInteractive = true;
            if (tabindex !== null && parseInt(tabindex) >= 0) isInteractive = true;

            if (isInteractive) {
                const childTag = node.tagName.toLowerCase();
                const parentTag = tag;
                return {
                    pass: false,
                    message: `Element <${childTag}> is invalidly nested inside interactive element <${parentTag}>`
                };
            }

            current = current.parentElement;
        }

        return { pass: true };
    }
};

module.exports = [check];
