const check = {
    id: 'aria-required-children',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element owns the required child roles',
            fail: 'Detailed ARIA structure is broken. The element is missing required child roles for its role type. Add the necessary children (e.g., a `list` needs `listitem`).'
        }
    },
    evaluate: function (node, options) {
        const { roles } = require('../../utils/aria-definitions');
        const role = node.getAttribute('role');

        if (!role || !roles[role] || !roles[role].requiredOwned) {
            return { pass: true };
        }

        const requiredOwned = roles[role].requiredOwned;
        const root = node.getRootNode ? node.getRootNode() : (node.ownerDocument || document);

        // helper: get logical children (skip role="none"/"presentation")
        function getLogicalChildren(el) {
            let logical = [];
            Array.from(el.children).forEach(child => {
                const childRole = child.getAttribute('role');
                if (childRole === 'none' || childRole === 'presentation' || (!childRole && ['DIV', 'SPAN'].includes(child.tagName))) {
                    logical.push(...getLogicalChildren(child));
                } else {
                    logical.push(child);
                }
            });
            return logical;
        }

        // 1. Get logical children from DOM
        let logicalChildren = getLogicalChildren(node);

        // 2. Add logically owned children via aria-owns
        const owns = node.getAttribute('aria-owns');
        if (owns) {
            const ownedIds = owns.trim().split(/\s+/);
            ownedIds.forEach(id => {
                const el = root.getElementById(id);
                if (el && !logicalChildren.includes(el)) {
                    logicalChildren.push(el);
                }
            });
        }

        // Special handling for combobox (ARIA 1.2 pattern)
        if (role === 'combobox') {
            const controls = node.getAttribute('aria-controls');
            if (controls) {
                const controlledIds = controls.trim().split(/\s+/);
                controlledIds.forEach(id => {
                    const el = root.getElementById(id);
                    if (el && !logicalChildren.includes(el)) {
                        logicalChildren.push(el);
                    }
                });
            }
        }

        // 3. Check for missing required children among logical children
        const hasRequired = logicalChildren.some(child => {
            const childRole = child.getAttribute('role');
            return requiredOwned.includes(childRole);
        });

        if (!hasRequired) {
            return {
                pass: false,
                message: `Element with role "${role}" is missing required logical children: ${requiredOwned.join(' or ')}`
            };
        }

        // 4. Check for disallowed children among logical children
        const disallowed = [];
        logicalChildren.forEach(child => {
            const childRole = child.getAttribute('role');
            if (childRole && !requiredOwned.includes(childRole)) {
                // Some roles like group are often allowed as wrappers
                if (childRole !== 'group') {
                    disallowed.push(`[role="${childRole}"]`);
                }
            }
        });

        if (disallowed.length > 0) {
            return {
                pass: false,
                message: `Element has logical children which are not allowed: ${disallowed.join(', ')}`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
