const dom = require('../../utils/dom');

const check = {
    id: 'svg-img-alt',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'SVG with role="img" has an accessible name',
            fail: 'SVG image is missing an accessible name. Screen readers cannot describe this graphic. Add `aria-label`, `aria-labelledby`, or a `<title>` element.'
        }
    },
    selector: 'svg[role="img"]',
    evaluate: function (node) {
        // We use computeAccessibleName or similar logic. 
        // For simplicity/robustness mirroring Axe: check aria-label, aria-labelledby, or title tag.

        let accName = '';
        if (dom && dom.computeAccessibleName) {
            accName = dom.computeAccessibleName(node);
        } else {
            // Fallback if acc-name util not available (it should be)
            const name = require('../../utils/acc-name');
            if (name && name.computeAccessibleName) {
                accName = name.computeAccessibleName(node);
            }
        }

        if (accName && accName.trim().length > 0) return { pass: true };

        // Even if computeAccessibleName fails (e.g. hidden?), we check strictly for presence of labeling technique?
        // Actually, if it has no accessible name, it fails.
        // Axe 'svg-img-alt' checks: aria-label, aria-labelledby, title element.

        // Let's rely on computeAccessibleName as it covers all valid ways (including title element).
        // But double check manual properties just in case computeAccessibleName isn't robust enough in this env (JSDOM issues again?)
        // Just like `svg-aria-label` rule we saw earlier.

        if (node.hasAttribute('aria-label') && node.getAttribute('aria-label').trim()) return { pass: true };
        if (node.hasAttribute('aria-labelledby') && node.getAttribute('aria-labelledby').trim()) return { pass: true };

        const title = node.querySelector('title');
        if (title && title.textContent.trim()) return { pass: true };

        return {
            pass: false,
            message: 'SVG with role="img" requires a title, aria-label, or aria-labelledby'
        };
    }
};

module.exports = [check];
