/**
 * Checks for image-alt-required
 */
const Check = require('../../core/check');

const check = new Check({
    id: 'image-alt-required-check',
    metadata: {
        messages: {
            pass: 'Image has a meaningful alternative text',
            fail: 'Image elements must have a meaningful non-empty alt attribute'
        }
    },
    evaluate: function (node, options) {
        if (!node || (node.tagName !== 'IMG' && node.tagName !== 'img')) return true; // not applicable here

        // Allow decorative images
        const ariaHidden = node.getAttribute('aria-hidden') === 'true';
        const role = (node.getAttribute('role') || '').toLowerCase();
        if (ariaHidden || role === 'presentation' || role === 'none') {
            const alt = node.getAttribute('alt');
            return alt === '' || alt === null || alt === undefined; // decorative should have empty or no alt
        }

        // Primary checks for meaningful alternatives
        const alt = node.getAttribute('alt');
        const ariaLabel = node.getAttribute('aria-label');
        const ariaLabelledby = node.getAttribute('aria-labelledby');

        // Helper: Check if text is meaningful
        const isMeaningful = (txt) => {
            if (typeof txt !== 'string') return false;
            const trimmed = txt.trim();
            if (trimmed.length === 0) return false; // Empty or whitespace only
            if (txt.startsWith(' ')) return false; // Starts with space (legacy check)
            return true;
        };

        // Helper: Check for suspicious patterns
        const getSuspiciousReason = (txt) => {
            if (!txt) return null;
            const trimmed = txt.trim();
            const lower = trimmed.toLowerCase();

            // 1. Junk / Symbols Check
            // Flags if text is just symbols/punctuation or numbers (e.g. ".", "???", "- ", "1")
            // Regex: /^[^\p{L}\p{N}\s]+$/u matches if the entire string consists of characters that are NOT letters, NOT numbers, and NOT whitespace.
            if (/^[^\p{L}\p{N}\s]+$/u.test(trimmed) || /^[\p{N}\s]+$/u.test(trimmed)) {
                return 'Alt text consists only of symbols or numbers, which provides no context to screen readers. Describe the image content or use alt="" if decorative.';
            }

            // 2. Generic Placeholders
            const placeholders = [
                'image', 'picture', 'photo', 'spacer', 'undefined', 'null',
                'placeholder', 'logo', 'hero image', 'banner', 'profile'
            ];
            // Check exact match or "image of..." patterns?
            // For now, exact bad words or very simple phrases
            if (placeholders.includes(lower) || placeholders.some(p => lower === `image of ${p}`)) {
                return `Alt text is a generic placeholder ("${trimmed}"). Describe the specific content of the image.`;
            }

            // 3. Suspicious Single Word (likely filename or hash)
            // > 15 chars, no spaces, contains non-alpha characters
            // Use \p{L} to match any Unicode letter
            if (trimmed.indexOf(' ') === -1 && trimmed.length > 15 && /[^\p{L}]/u.test(trimmed)) {
                return 'Alt text appears to be a filename or random string. User-facing text should describe the image content.';
            }

            // 4. Filename Pattern (Existing + Enhanced)
            // Allow spaces (for "my image.png") but ensure it ends with extension
            // Added 'jepg' as common typo
            if (/^[a-zA-Z0-9_\-\.\s]+\.(jpg|jpeg|jepg|png|gif|webp|svg|bmp|tiff|ico)$/i.test(trimmed)) {
                return 'Alt text appears to be a filename. User-facing text should describe the image content, not the file source.';
            }


            return null;
        };

        // 1. Check if any accessible name source exists and is meaningful
        const altValid = isMeaningful(alt);
        const ariaLabelValid = isMeaningful(ariaLabel);
        const ariaLabelledbyValid = isMeaningful(ariaLabelledby);

        if (!node.hasAttribute('alt') && !node.hasAttribute('aria-label') && !node.hasAttribute('aria-labelledby')) {
            return true; // Delegate to image-alt rule
        }

        if (!altValid && !ariaLabelValid && !ariaLabelledbyValid) {
            return {
                pass: false,
                message: 'Image is missing a meaningful accessible name. If the image is decorative, use alt="" or role="presentation".'
            };
        }

        // 2. Enhanced Quality Checks for Alt Text
        if (altValid) {
            const trimmedAlt = alt.trim();

            // A. Redundancy Checks
            // duplicate title
            const title = node.getAttribute('title');
            if (title && title.trim() === trimmedAlt) {
                return {
                    pass: false,
                    message: 'Alt text is identical to the title attribute. This causes screen readers to announce the same text twice. Remove the title attribute or ensure alt provides unique context.'
                };
            }

            // duplicate figcaption
            let parent = node.parentElement;
            // Traverse up slightly to find Figure
            let depth = 0;
            while (parent && depth < 3) {
                if (parent.tagName === 'FIGURE') {
                    const figcaption = parent.querySelector('figcaption');
                    if (figcaption && figcaption.textContent.trim() === trimmedAlt) {
                        return {
                            pass: false,
                            message: 'Alt text repeats the figure caption. Since the caption already describes the image, set alt="" to avoid redundancy.'
                        };
                    }
                    break;
                }
                parent = parent.parentElement;
                depth++;
            }

            // B. Content Heuristics
            const suspiciousReason = getSuspiciousReason(trimmedAlt);
            if (suspiciousReason) {
                return {
                    pass: false,
                    message: `Alt text is not meaningful: ${suspiciousReason}`
                };
            }
        }

        // 3. Check aria-label quality if it's the primary source
        if (!altValid && ariaLabelValid) {
            const suspiciousReason = getSuspiciousReason(ariaLabel);
            if (suspiciousReason) {
                return {
                    pass: false,
                    message: `Aria-label is not meaningful: ${suspiciousReason}`
                };
            }
        }

        return true;
    }
});

module.exports = [check];
