const Check = require('../../core/check');

const ariaHiddenBody = new Check({
    id: 'aria-hidden-body',
    metadata: {
        messages: {
            pass: 'Body does not have aria-hidden="true"',
            fail: 'The `<body>` element is hidden (`aria-hidden="true"`). This makes the entire page invisible to screen readers. Remove the `aria-hidden` attribute from `<body>`.'
        }
    },
    evaluate: function (node) {
        const ariaHidden = node.getAttribute('aria-hidden');
        if (ariaHidden && ariaHidden.toLowerCase() === 'true') {
            return false;
        }
        return true;
    }
});

module.exports = [ariaHiddenBody];
