const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasAlt = new Check({
    id: 'area-has-alt',
    metadata: {
        messages: {
            pass: 'Area element has accessible text',
            fail: 'Area element detected without text. Image map links must have alternative text for screen reader compatibility. Add an `alt` attribute describing the link purpose.'
        }
    },
    evaluate: function (node) {
        return !!dom.computeAccessibleName(node);
    }
});

module.exports = [hasAlt];
