const Check = require('../../core/check');

const blinkPresent = new Check({
    id: 'blink-present',
    metadata: {
        messages: {
            pass: 'No blink element present', // Technically never reached if selector matches
            fail: 'Blink element is present. Blinking content causes seizures and distractions. Remove the `<blink>` element or update CSS to avoid blinking.'
        }
    },
    evaluate: function (node) {
        return false;
    }
});

module.exports = [blinkPresent];
