/**
 * Checks for aria-input-field-name
 */
const Check = require('../../core/check');
const a11y = require('../../utils/a11y');

const ariaInputFieldCheck = new Check({
    id: 'aria-input-field-name',
    metadata: {
        impact: 'critical',
        messages: {
            pass: 'ARIA input field has an accessible name',
            fail: 'ARIA input field is missing an accessible name. Screen readers cannot identify the purpose of this input. Add `aria-label` or `aria-labelledby`.'
        }
    },
    evaluate: function (node) {
        // Roles that act as input fields
        const inputRoles = ['combobox', 'listbox', 'searchbox', 'slider', 'spinbutton', 'textbox'];
        const role = node.getAttribute('role');

        if (!inputRoles.includes(role)) return true; // Not an input field role

        const name = a11y.getAccessibleName(node);
        return name && name.length > 0;
    }
});

module.exports = [ariaInputFieldCheck];
