const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasAlt = new Check({
    id: 'object-alt',
    metadata: {
        messages: {
            pass: 'Object element has accessible text',
            fail: 'Object element is missing accessible text. Screen readers cannot convey its content. Provide alternative text content inside the `<object>` tag.'
        }
    },
    evaluate: function (node) {
        return !!dom.computeAccessibleName(node);
    }
});

module.exports = [hasAlt];
