/**
 * Checks for image-redundant-alt
 */
const Check = require('../../core/check');

const imageRedundantAlt = new Check({
    id: 'image-redundant-alt',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'Image alt text is not redundant',
            fail: 'Redundant alt text detected. Words like "image of" or "picture of" clutter screen reader output. Remove these phrases from the `alt` text.'
        }
    },
    evaluate: function (node) {
        if (!node.hasAttribute('alt')) return true; // Handled by image-alt
        const alt = node.getAttribute('alt').trim().toLowerCase();
        if (alt.length === 0) return true; // Empty alt is not redundant in this sense (ignored)

        // 1. Check for redundant phrases
        const redundantWords = ['image of', 'picture of', 'photo of'];
        if (redundantWords.some(word => alt.startsWith(word))) {
            return {
                pass: false,
                message: 'Redundant alt text detected. Words like "image of" or "picture of" clutter screen reader output.'
            };
        }

        // 2. Check for adjacent text redundancy
        // Strategy: Check next sibling and previous sibling for text content matching the alt.
        function getAdjacentText(startNode, direction = 'next') {
            let current = startNode;
            while (current) {
                current = direction === 'next' ? current.nextSibling : current.previousSibling;
                if (!current) break;

                if (current.nodeType === 3) { // Text
                    const text = current.textContent.trim();
                    if (text.length > 0) return text.toLowerCase();
                } else if (current.nodeType === 1) { // Element
                    // Ignore hidden
                    const style = current.ownerDocument.defaultView ? current.ownerDocument.defaultView.getComputedStyle(current) : {};
                    if (style.display === 'none' || style.visibility === 'hidden') continue;

                    const text = current.textContent.trim();
                    if (text.length > 0) return text.toLowerCase();
                }
            }
            return null;
        }

        const nextText = getAdjacentText(node, 'next');
        const prevText = getAdjacentText(node, 'prev');

        if (nextText === alt || prevText === alt) {
            return {
                pass: false,
                message: 'Alt text matches adjacent text. This causes accessible technologies to read the same text twice.'
            };
        }

        return true;
    }
});

module.exports = [imageRedundantAlt];
