const check = {
    id: 'label-title-only',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Form field has a visible label or aria-label',
            fail: 'Form field should not rely solely on title attribute for labeling'
        }
    },
    evaluate: function (node, options) {
        // If node has no title, this rule doesn't fail (other rules check for missing label).
        // This rule specifically fails if title IS present AND it is the ONLY source of label.

        if (!node.hasAttribute('title')) return { pass: true };

        const hasAriaLabel = node.hasAttribute('aria-label') || node.hasAttribute('aria-labelledby');
        const hasIdLabel = node.id && node.ownerDocument.querySelector(`label[for="${node.id}"]`);
        const hasImplicitLabel = node.closest('label');

        if (!hasAriaLabel && !hasIdLabel && !hasImplicitLabel) {
            return { pass: false, message: 'Form field relies solely on title attribute' };
        }
        return { pass: true };
    }
};

module.exports = [check];
