    'combobox': { allowed: ['aria-autocomplete', 'aria-readonly', 'aria-required', 'aria-activedescendant', 'aria-orientation'], required: ['aria-expanded', 'aria-controls'], requiredOwned: ['listbox', 'tree', 'grid', 'dialog'] },
    'complementary': { allowed: ['aria-expanded'], required: [] },
    'contentinfo': { allowed: ['aria-expanded'], required: [] },
    'definition': { allowed: ['aria-expanded'], required: [] },
    'dialog': { allowed: ['aria-expanded', 'aria-modal'], required: [] },
    'directory': { allowed: ['aria-expanded'], required: [] },
