    'menubar': { allowed: ['aria-activedescendant', 'aria-expanded'], required: [], requiredOwned: ['menuitem', 'menuitemcheckbox', 'menuitemradio'] },
    'menuitem': { allowed: ['aria-posinset', 'aria-setsize'], required: [], requiredContext: ['menu', 'menubar'] },
    'menuitemcheckbox': { allowed: ['aria-posinset', 'aria-setsize'], required: ['aria-checked'], requiredContext: ['menu', 'menubar'] },
    'menuitemradio': { allowed: ['aria-posinset', 'aria-setsize', 'aria-selected'], required: ['aria-checked'], requiredContext: ['menu', 'menubar', 'group'] },
