/**
 * Accessible Name Computation
 * Based on W3C AccName 1.1
 */

/**
 * Compute the accessible name of an element
 * @param {HTMLElement} element 
 * @param {Object} options 
 * @returns {string}
 */
function computeAccessibleName(element, options = {}) {
    if (!element) return '';

    // 1. aria-labelledby
    if (element.hasAttribute('aria-labelledby')) {
        const doc = element.ownerDocument || document; // Fallback to global if owner is missing (rare)
        const ids = element.getAttribute('aria-labelledby').split(/\s+/);
        const parts = ids.map(id => {
            const ref = doc.getElementById(id);
            return ref ? computeAccessibleName(ref, { ...options, recursion: true }) : '';
        });
        const name = parts.filter(s => s).join(' ');
        if (name) return name;
    }

    // 2. aria-label
    if (element.hasAttribute('aria-label')) {
        const label = element.getAttribute('aria-label').trim();
        if (label) return label;
    }

    // 3. Native labeling (simplified for common elements)
    const tagName = element.tagName.toLowerCase();

    // Form controls with label[for]
    if (['input', 'textarea', 'select', 'button'].includes(tagName)) {
        if (element.id) {
            const doc = element.ownerDocument || document;
            const label = doc.querySelector(`label[for="${element.id}"]`);
            if (label) {
                return computeAccessibleName(label, { ...options, recursion: true });
            }
        }
        // Implicit label
        const parentLabel = element.closest('label');
        if (parentLabel) {
            return computeAccessibleName(parentLabel, { ...options, recursion: true });
        }
    }

    // Images
    if (tagName === 'img') {
        if (element.hasAttribute('alt')) return element.getAttribute('alt');
        if (element.hasAttribute('title')) return element.getAttribute('title');
        return ''; // No name
    }

    // Area
    if (tagName === 'area') {
        if (element.hasAttribute('alt')) return element.getAttribute('alt');
        // Fall through to other steps (title, etc) if alt is missing
    }

    // Inputs
    if (tagName === 'input') {
        if (element.type === 'image' && element.hasAttribute('alt')) return element.getAttribute('alt');
        if (element.type === 'submit' || element.type === 'button') return element.value || 'Submit';
    }

    // 4. Name from content
    // Only if not hidden. 
    // Optimization: if role/tag doesn't support name from content, we might skip logic, but we must do specific hidden checks?
    // Spec says: if hidden and not referenced by aria-labelledby, return empty.
    if (!options.recursion && isHidden(element)) return '';

    // If it's a control that gets name from content (button, link, etc)
    // or if we are recursing (calculating label text)
    if (options.recursion || supportsNameFromContent(element)) {
        let text = '';
        // Walk children
        element.childNodes.forEach(child => {
            if (child.nodeType === 3) { // Text node
                text += child.textContent;
            } else if (child.nodeType === 1) { // Element
                // Checks for CSS content would go here
                // Recurse
                text += ' ' + computeAccessibleName(child, { ...options, recursion: true });
            }
        });
        const trimmed = text.trim().replace(/\s+/g, ' ');
        if (trimmed) return trimmed;
    }

    // 5. Title attribute (fallback)
    if (element.hasAttribute('title')) {
        return element.getAttribute('title');
    }

    return '';
}

function isHidden(element) {
    if (element.nodeType !== 1) return false;
    const win = element.ownerDocument && element.ownerDocument.defaultView ? element.ownerDocument.defaultView : (typeof window !== 'undefined' ? window : null);
    if (!win) return false; // Cannot determine, assume visible?

    const style = win.getComputedStyle(element);

    // Area elements are technically display:none in most user agents but considered visible/interactive for a11y
    const isArea = element.tagName.toLowerCase() === 'area';
    if (!isArea && (style.display === 'none' || style.visibility === 'hidden')) return true;

    return element.getAttribute('aria-hidden') === 'true';
}

function supportsNameFromContent(element) {
    const tagName = element.tagName.toLowerCase();
    const role = element.getAttribute('role');

    // List of roles/tags that support name from content
    const supportedTags = ['button', 'a', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'label', 'span', 'div', 'p', 'li', 'td', 'th', 'object'];
    if (supportedTags.includes(tagName)) return true;
    if (role && ['button', 'link', 'heading', 'checkbox', 'radio', 'switch', 'tab', 'treeitem'].includes(role)) return true;

    return false;
}

module.exports = {
    computeAccessibleName
};
