const check = {
    id: 'css-orientation-lock',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'CSS Media queries do not lock display orientation',
            fail: 'CSS Media queries must not lock display orientation'
        }
    },
    evaluate: function (node, options) {
        const doc = node.ownerDocument;
        // Check link elements with media attribute
        const links = Array.from(doc.querySelectorAll('link[rel="stylesheet"]'));
        for (const link of links) {
            const media = link.getAttribute('media');
            if (media && media.includes('orientation:')) {
                // Heuristic: if orientation is present, it might be locking
                return { pass: false, message: 'Orientation lock detected in link media attribute' };
            }
        }

        // Check style elements
        const styles = Array.from(doc.querySelectorAll('style'));
        for (const style of styles) {
            if (style.textContent.includes('@media') && style.textContent.includes('orientation:')) {
                return { pass: false, message: 'Orientation lock detected in style tag' };
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
