const check = {
    id: 'text-spacing',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'No inline fixed height with overflow hidden found on text container',
            fail: 'Element has inline fixed height/max-height and overflow:hidden, which may truncate text when spacing is increased (WCAG 1.4.12)'
        }
    },
    selector: '[style]',
    evaluate: function (node) {
        // WCAG 1.4.12: Text Spacing
        // Failure: Fixed height + overflow hidden on elements containing text.
        // This check focuses on inline styles which are definitive indicators of rigid authorship.

        const excludeTags = ['IMG', 'SVG', 'VIDEO', 'AUDIO', 'CANVAS', 'INPUT', 'TEXTAREA', 'SELECT', 'IFRAME', 'SCRIPT', 'STYLE', 'LINK'];
        if (excludeTags.includes(node.tagName)) return { pass: true };

        const s = node.style;
        if (!s) return { pass: true };

        // Check specifically for overflow hidden
        // Check specifically for overflow hidden
        const isHidden = (s.overflow === 'hidden' || s.overflowY === 'hidden');
        if (!isHidden) return { pass: true };

        // Check for fixed height or max-height
        // We consider it fixed if it's set to anything other than 'auto' or 'none' (for max-height) and is not empty.
        // This catches px, em, %, vh etc. If it's 100% it might be okay but often risks cutoff if parent is fixed.
        // We'll be strict: any explicit height + overflow hidden is a risk for text spacing.
        const h = s.height;
        const mh = s.maxHeight;

        const hasFixedHeight = (h && h !== 'auto' && h.trim() !== '') ||
            (mh && mh !== 'none' && mh.trim() !== '');

        if (hasFixedHeight) {
            // Only fail if there is text content to be cut off
            if (node.textContent && node.textContent.trim().length > 0) {
                return { pass: false };
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
