const Rule = require('./rule');

class RuleManager {
    constructor() {
        this.rules = new Map();
    }

    /**
     * Register a new rule
     * @param {Object} ruleConfig 
     */
    addRule(ruleConfig) {
        if (!ruleConfig.id) {
            throw new Error('Rule must have an ID');
        }
        this.rules.set(ruleConfig.id, new Rule(ruleConfig));
    }

    /**
     * Get a rule by ID
     * @param {string} id 
     * @returns {Rule}
     */
    getRule(id) {
        return this.rules.get(id);
    }

    /**
     * Get all registered rules
     * @returns {Rule[]}
     */
    getRules() {
        return Array.from(this.rules.values());
    }

    /**
     * Clear all rules
     */
    clear() {
        this.rules.clear();
    }
}

module.exports = RuleManager;
