const check = {
    id: 'avoid-inline-spacing',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'No !important text spacing styles found',
            fail: 'Fixed text spacing detected. using `!important` on text properties prevents low-vision users from overriding them. Remove `!important` from `line-height`, `letter-spacing`, and `word-spacing`.'
        }
    },
    selector: '[style]',
    evaluate: function (node) {
        // WCAG 1.4.12 Text Spacing
        // Ensure that line-height, letter-spacing, word-spacing are not set with !important in inline styles.
        // This prevents users from overriding them.

        const style = node.getAttribute('style');
        if (!style) return { pass: true };

        // We need to parse the style string to find !important declarations for specific properties.
        // Regex is safer than style object because !important might not be preserved or accessible easily via node.style in all envs (though usually it is).
        // node.style.getPropertyPriority('line-height') returns 'important' if set.

        if (typeof node.style === 'object') {
            const properties = ['line-height', 'letter-spacing', 'word-spacing'];
            const failingProps = [];

            for (const prop of properties) {
                if (node.style.getPropertyPriority(prop) === 'important') {
                    failingProps.push(prop);
                }
            }

            if (failingProps.length > 0) {
                return {
                    pass: false,
                    message: `The following properties are set with !important in inline style: ${failingProps.join(', ')}`
                };
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
