/**
 * Rule: meta-viewport
 * Ensures <meta name="viewport"> does not disable text scaling and zooming
 */
const checks = require('./checks');

module.exports = {
    id: 'meta-viewport',
    selector: 'meta[name="viewport"]',
    metadata: {
        description: 'Ensures <meta name="viewport"> does not disable text scaling. Blocking zoom prevents low-vision users from reading content.',
        help: 'Zooming and scaling must not be disabled',
        helpUrl: 'https://dequeuniversity.com/rules/axe/4.4/meta-viewport',
        impact: 'critical'
    },
    tags: ['cat.sensory-and-visual-cues', 'wcag2aa', 'wcag144', 'gigw-3.0:5.2.15', 'is-17802:9.1.4.4'],
    any: ['meta-viewport-check'],
    checks: checks
};
