/**
 * Checks for link-name
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasName = new Check({
    id: 'link-has-name',
    metadata: {
        messages: {
            pass: 'Link has discernible text',
            fail: 'Link is missing discernible text. Screen readers cannot describe the link\'s destination. Add text content, `aria-label`, or an `alt` attribute to the image inside.'
        }
    },
    evaluate: function (node) {
        const name = dom.computeAccessibleName(node);
        if (name) return true;

        return {
            pass: false,
            message: 'This link does not have any discernible text. Screen readers may announce it as "link" or read the URL. Add descriptive text or an aria-label.'
        };
    }
});

const isHidden = new Check({
    id: 'is-hidden-link',
    metadata: {
        messages: {
            pass: 'Link is hidden',
            fail: 'Link is visible and functional but lacks an accessible name. Blind users will encounter it but hear nothing. Ensure it has text or a label.'
        }
    },
    evaluate: function (node) {
        return !dom.isVisible(node);
    }
});

module.exports = [hasName, isHidden];
