/**
 * Checks for role-img-alt
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const roleImgAlt = new Check({
    id: 'role-img-alt',
    metadata: {
        messages: {
            pass: 'Element with role="img" has an accessible name',
            fail: 'Element with `role="img"` is missing an accessible name. Screen readers cannot describe the image. Add `aria-label` or `aria-labelledby`.'
        }
    },
    evaluate: function (node) {
        return !!dom.computeAccessibleName(node);
    }
});

module.exports = [roleImgAlt];
