/**
 * Checks for button-name
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasName = new Check({
    id: 'button-has-name',
    metadata: {
        messages: {
            pass: 'Button has an accessible name',
            fail: 'Button is missing an accessible name. Screen reader users will not know the button\'s purpose. Add text content, `aria-label`, or `aria-labelledby`.'
        }
    },
    evaluate: function (node) {
        const name = dom.computeAccessibleName(node);
        if (name) return true;

        return {
            pass: false,
            message: 'This button does not have a comprehensive name. If it is an icon-only button, use aria-label to describe its function (e.g., "Close menu").'
        };
    }
});

const isHidden = new Check({
    id: 'is-hidden',
    metadata: {
        messages: {
            pass: 'Element is hidden',
            fail: 'Button is visible but lacks an accessible name. Screen reader users will hear "button" without context. Add a label.'
        }
    },
    evaluate: function (node) {
        return !dom.isVisible(node);
    }
});

module.exports = [hasName, isHidden];
