const dom = require('../../utils/dom');

const check = {
    id: 'identical-links-same-purpose',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'Links with the same name go to the same URL',
            fail: 'Ambiguous link destination. Links with the same name point to different URLs, confusing users. Ensure identical link text targets the same resource.'
        }
    },
    evaluate: function (node, options) {
        const name = dom.computeAccessibleName(node);
        if (!name) return { pass: true }; // defer to link-name rule

        const href = node.getAttribute('href');
        if (!href) return { pass: true }; // defer to other rules

        const root = node.getRootNode ? node.getRootNode() : document;
        const allLinks = Array.from(root.querySelectorAll('a'));

        // Find other links with same name
        const conflict = allLinks.find(other => {
            if (other === node) return false;
            const otherName = dom.computeAccessibleName(other);
            if (otherName !== name) return false;

            const otherHref = other.getAttribute('href');
            // Compare hrefs (basic string comparison for now, ideally resolve to absolute)
            return otherHref !== href;
        });

        if (conflict) {
            return { pass: false, message: `Link "${name}" has different destination than other link` };
        }

        return { pass: true };
    }
};

module.exports = [check];
