/**
 * V2 Reporter
 * Returns a simplified results object (example)
 * @param {Object} results 
 * @param {Object} options 
 * @returns {Object}
 */
function v2(results, options) {
    // Example transformation: just return violations and passes count
    return {
        violations: results.violations,
        passes: results.passes,
        meta: {
            timestamp: results.timestamp,
            engine: results.testEngine
        }
    };
}

module.exports = v2;
