/**
 * ARIA Utilities for role resolution
 */

const { roles: roleDefinitions } = require('./aria-definitions');

/**
 * Get the implicit ARIA role of an element based on its tag name and attributes.
 * @param {HTMLElement} element 
 * @returns {string|null}
 */
function getImplicitRole(element) {
    const tagName = element.tagName.toLowerCase();

    switch (tagName) {
        case 'article': return 'article';
        case 'aside': return 'complementary';
        case 'button': return 'button';
        case 'datalist': return 'listbox';
        case 'dd': return 'definition';
        case 'details': return 'group';
        case 'dialog': return 'dialog';
        case 'dl': return 'list';
        case 'dt': return 'term';
        case 'fieldset': return 'group';
        case 'figure': return 'figure';
        case 'footer': {
            // footer is contentinfo only if not a descendant of article, aside, main, nav or section
            const isScoped = !!element.closest('article, aside, main, nav, section');
            return isScoped ? null : 'contentinfo';
        }
        case 'form': return 'form';
        case 'header': {
            // header is banner only if not a descendant of article, aside, main, nav or section
            const isScoped = !!element.closest('article, aside, main, nav, section');
            return isScoped ? null : 'banner';
        }
        case 'hr': return 'separator';
        case 'html': return 'document';
        case 'img':
            if (element.getAttribute('alt') === '') return 'presentation';
            return 'img';
        case 'input': {
            const type = (element.getAttribute('type') || 'text').toLowerCase();
            switch (type) {
                case 'button':
                case 'image':
                case 'reset':
                case 'submit': return 'button';
                case 'checkbox': return 'checkbox';
                case 'number': return 'spinbutton';
                case 'radio': return 'radio';
                case 'range': return 'slider';
                case 'search':
                    return element.hasAttribute('list') ? 'combobox' : 'searchbox';
                case 'tel':
                case 'text':
                case 'url':
                case 'email':
                case 'password':
                    return element.hasAttribute('list') ? 'combobox' : 'textbox';
                default: return 'textbox';
            }
        }
        case 'li': return 'listitem';
        case 'main': return 'main';
        case 'menu': return 'list';
        case 'nav': return 'navigation';
        case 'ol': return 'list';
        case 'option': return 'option';
        case 'output': return 'status';
        case 'progress': return 'progressbar';
        case 'section': return 'region';
        case 'select': return 'listbox'; // simplified
        case 'summary': return 'button';
        case 'table': return 'table';
        case 'tbody': return 'rowgroup';
        case 'textarea': return 'textbox';
        case 'tfoot': return 'rowgroup';
        case 'th': return 'columnheader'; // or rowheader
        case 'thead': return 'rowgroup';
        case 'tr': return 'row';
        case 'ul': return 'list';
        case 'h1':
        case 'h2':
        case 'h3':
        case 'h4':
        case 'h5':
        case 'h6': return 'heading';
        default: return null;
    }
}

/**
 * Check if the native HTML element provides the semantics of an ARIA attribute.
 * @param {HTMLElement} element 
 * @param {string} attribute 
 * @returns {boolean}
 */
function isAttributeSatisfiedByNative(element, attribute) {
    const tagName = element.tagName.toLowerCase();
    const type = (element.getAttribute('type') || 'text').toLowerCase();

    if (attribute === 'aria-level') {
        return ['h1', 'h2', 'h3', 'h4', 'h5', 'h6'].includes(tagName);
    }
    if (attribute === 'aria-checked') {
        return tagName === 'input' && ['checkbox', 'radio'].includes(type);
    }
    if (attribute === 'aria-valuemax' || attribute === 'aria-valuemin' || attribute === 'aria-valuenow') {
        return tagName === 'input' && ['number', 'range', 'date', 'month', 'week', 'time', 'datetime-local'].includes(type);
    }
    if (attribute === 'aria-placeholder') {
        return (tagName === 'input' || tagName === 'textarea') && element.hasAttribute('placeholder');
    }
    if (attribute === 'aria-disabled') {
        return element.hasAttribute('disabled');
    }
    if (attribute === 'aria-readonly') {
        return element.hasAttribute('readonly');
    }
    if (attribute === 'aria-required') {
        return element.hasAttribute('required');
    }
    return false;
}

/**
 * Get the effective ARIA role of an element.
 * @param {HTMLElement} element 
 * @returns {string|null}
 */
function getRole(element) {
    const explicitRole = element.getAttribute('role');
    if (explicitRole) {
        // Validate if it's a known role
        if (roleDefinitions[explicitRole]) {
            return explicitRole;
        }
    }
    return getImplicitRole(element);
}

module.exports = {
    getImplicitRole,
    getRole,
    isAttributeSatisfiedByNative
};
