const check = {
    id: 'aria-deprecated-role',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'Role is not deprecated',
            fail: 'Deprecated ARIA role used. This role is no longer supported and may cause issues. Update to a non-deprecated role.'
        }
    },
    selector: '[role]',
    evaluate: function (node) {
        const role = node.getAttribute('role');
        if (!role) return { pass: true };

        const deprecatedRoles = ['directory', 'expansion', 'flat', 'landmark']; // Common deprecated ones in ARIA 1.1/1.2+
        // Note: 'landmark' role is abstract, not deprecated for use? actually it IS abstract so shouldn't be used anyway.
        // Axe checks: directory.

        if (deprecatedRoles.includes(role)) {
            return {
                pass: false,
                message: `The role "${role}" is deprecated`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
