/**
 * Checks for audio-caption
 */
const Check = require('../../core/check');

const hasCaptions = new Check({
    id: 'audio-caption',
    metadata: {
        messages: {
            pass: 'Audio element has captions',
            fail: 'Audio is missing captions. Deaf and hard-of-hearing users cannot consume this content. Add a `<track kind="captions">` element.'
        }
    },
    evaluate: function (node) {
        // Check for track element with kind="captions"
        const tracks = node.querySelectorAll('track[kind="captions"]');
        if (tracks.length > 0) return true;

        return {
            incomplete: true,
            message: 'Audio captions not found, manual review required'
        };
    }
});

module.exports = [hasCaptions];
