const check = {
    id: 'aria-keyshortcuts',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'aria-keyshortcuts syntax is valid',
            fail: 'aria-keyshortcuts must be a space-separated list of valid key combinations'
        }
    },
    selector: '[aria-keyshortcuts]',
    evaluate: function (node) {
        const val = node.getAttribute('aria-keyshortcuts');
        if (!val || !val.trim()) return { pass: true };

        const shortcuts = val.trim().split(/\s+/);

        // Allowed keys (basic validation)
        const validUnmodifiedKeys = /^[A-Za-z0-9]$/; // Single char
        const validModifiers = ['Shift', 'Control', 'Alt', 'Meta'];
        // Modifiers must be combined with a key via '+' e.g. "Shift+A"

        // Full regex approach for a single shortcut token?
        // e.g. (Modifier\+)+Key

        for (const shortcut of shortcuts) {
            // Check if valid
            // Axe logic implies e.g. "A", "Shift+A", "Control+Alt+B"
            // "Plus" is literal "+"
            // "Space" is literal " " (but shortcuts are space separated, so "Space" keyword?)

            // Simplified validation:
            // Must not end with +.
            if (shortcut.endsWith('+')) {
                return { pass: false, message: `Invalid shortcut: "${shortcut}"` };
            }

            const parts = shortcut.split('+');
            if (parts.length === 0) return { pass: false };

            for (const part of parts) {
                if (!part.trim()) return { pass: false, message: 'Empty key part' };
            }
        }

        return { pass: true };
    }
};

module.exports = [check];
