const Check = require('../../core/check');

const marqueePresent = new Check({
    id: 'marquee-present',
    metadata: {
        messages: {
            pass: 'No marquee element present',
            fail: 'Marquee element is present. Moving content is difficult to read and distracting. Remove the `<marquee>` element and use static content or accessible CSS animations.'
        }
    },
    evaluate: function (node) {
        return false;
    }
});

module.exports = [marqueePresent];
