/**
 * Checks for input-button-name
 */
const Check = require('../../core/check');
const a11y = require('../../utils/a11y');

const inputButtonName = new Check({
    id: 'input-button-name',
    metadata: {
        impact: 'critical',
        messages: {
            pass: 'Input button has an accessible name',
            fail: 'Input button is missing an accessible name. Screen reader users will not know its function. Add a `value` attribute or `aria-label`.'
        }
    },
    evaluate: function (node) {
        // Only checking input types button, submit, reset
        const type = node.getAttribute('type');
        if (!['button', 'submit', 'reset'].includes(type)) return true;

        const name = a11y.getAccessibleName(node);
        // Also check value attribute specifically as it's the primary label for these inputs
        const hasValue = node.hasAttribute('value') && node.getAttribute('value').trim().length > 0;

        return (name && name.length > 0) || hasValue;
    }
});

module.exports = [inputButtonName];
