const check = {
    id: 'radiogroup',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Radio input is grouped',
            fail: 'Radio input must be contained in a <fieldset> or element with role="radiogroup" to group related options.'
        }
    },
    selector: 'input[type="radio"]',
    evaluate: function (node) {
        // If it's in a group, pass immediately
        if (node.closest('fieldset, [role="radiogroup"]')) {
            return { pass: true };
        }

        // It is NOT in a group.
        // Check if there are other radios with the same name.
        const name = node.getAttribute('name');
        if (!name) return { pass: true }; // No name, can't group by name.

        // Escape name logic for selector
        const updatesName = name.replace(/"/g, '\\"');
        const selector = `input[type="radio"][name="${updatesName}"]`;
        const others = node.ownerDocument.querySelectorAll(selector);

        if (others.length > 1) {
            // Multiple radios share this name, but this one is not grouped.
            return {
                pass: false,
                message: `Radio group "${name}" has ${others.length} inputs but is not grouped in a fieldset`
            };
        }

        // Single radio? 
        // Technically strict WCAG might allow single radio without fieldset if it has label.
        // We'll pass single instances to avoid false positives on 'toggle-like' single radios.
        return { pass: true };
    }
};

module.exports = [check];
