const check = {
    id: 'presentation-role-conflict',
    metadata: {
        impact: 'minor',
        messages: {
            pass: 'Element with presentation role is not focusable',
            fail: 'Element with presentation role must not be focusable'
        }
    },
    evaluate: function (node, options) {
        if (node.hasAttribute('tabindex') && parseInt(node.getAttribute('tabindex')) >= 0) {
            return { pass: false, message: 'Element has focusable tabindex' };
        }

        // Check implicit focusability (e.g., link with href, button, input)
        const tag = node.tagName.toLowerCase();
        const focusableTags = ['a', 'button', 'input', 'select', 'textarea', 'details', 'embed', 'iframe', 'label', 'audio', 'video'];

        if (focusableTags.includes(tag)) {
            if (tag === 'a' && !node.hasAttribute('href')) return { pass: true };
            return { pass: false, message: `Element <${tag}> implies focusability` };
        }

        return { pass: true };
    }
};

module.exports = [check];
