const check = {
    id: 'aria-required-parent',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element has the required parent role',
            fail: 'Orphaned ARIA role. The element is missing a required parent role. Wrap this element in a container with the appropriate parent role (e.g., `listitem` inside `list`).'
        }
    },
    evaluate: function (node, options) {
        const { roles } = require('../../utils/aria-definitions');
        const role = node.getAttribute('role');

        if (!role || !roles[role] || !roles[role].requiredContext) {
            return { pass: true };
        }

        const requiredContext = roles[role].requiredContext;

        // Walk up the tree
        let parent = node.parentElement;
        let found = false;
        while (parent) {
            const parentRole = parent.getAttribute('role');
            if (parentRole && requiredContext.includes(parentRole)) {
                found = true;
                break;
            }
            parent = parent.parentElement;
            // Stop at body to prevent infinite loops (though parentElement should become null)
            if (parent && parent.tagName === 'BODY') break;
        }

        if (!found) {
            return {
                pass: false,
                message: `Element with role "${role}" must be contained in: ${requiredContext.join(' or ')}`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
