const Engine = require('./core/engine');
const Runner = require('./core/runner');
const Rule = require('./core/rule');
const logger = require('./logger');

// Initialize the global engine instance
const satya = new Engine();

// Register default rules
const rules = [
    ...require('./rules')
];

rules.forEach(rule => {
    satya.addRule(rule);
    if (rule.checks) {
        rule.checks.forEach(check => satya.addCheck(check));
    }
});

// Create the public API object
const api = {
    /**
     * @type {Engine}
     */
    _engine: satya, // Access to internal engine if needed

    /**
     * Configure the engine
     * @param {Object} configuration 
     */
    configure: (configuration) => {
        satya.configure(configuration);
        // Also configure logger if present
        if (configuration.logger) {
            logger.configure(configuration.logger);
        }
    },

    /**
     * Run the engine
     * @param {Element|String} context 
     * @param {Object} options 
     * @param {Function} callback 
     */
    run: (context, options, callback) => satya.run(context, options, callback),

    /**
     * Register a plugin
     */
    registerPlugin: (plugin) => satya.registerPlugin(plugin),

    /**
     * Reset configuration
     */
    reset: () => satya.reset(),

    getRules: () => satya.rules,

    /**
     * Logger instance
     */
    logger: logger
};

// Export the instance and classes for advanced usage
// Export the instance and classes for advanced usage
module.exports = api;
module.exports.Engine = Engine;
module.exports.Runner = Runner;
module.exports.Rule = Rule;
// New Features
module.exports.FocusAnalyzer = require('./core/focus-analyzer');
module.exports.FocusUtils = require('./utils/focus-utils');
module.exports.default = api; // For ES6 imports

// If running in a browser environment, attach to window
if (typeof window !== 'undefined') {
    window.satya = api;
}
