/**
 * Checks for p-as-heading
 */
const Check = require('../../core/check');

const pNotHeading = new Check({
    id: 'p-not-heading',
    metadata: {
        messages: {
            pass: 'Paragraph is not styled as a heading',
            fail: 'Paragraph appears to be styled as a heading. Use a heading element (h1-h6) instead.'
        }
    },
    evaluate: function (node) {
        const text = node.textContent.trim();
        if (!text) return true; // Ignore empty paragraphs

        const win = node.ownerDocument.defaultView;
        if (!win) return true;

        const style = win.getComputedStyle(node);
        const fontSizeStr = style.fontSize;
        const fontSize = parseFloat(fontSizeStr);
        const fontWeight = style.fontWeight;
        const isBold = fontWeight === 'bold' || parseInt(fontWeight) >= 700;

        // Heuristics:
        // Medium valid heading (H3) is usually ~18.72px (1.17em).
        // Let's flag if it is Bold AND >= 18px 
        // OR simply very large (>= 24px, H2 size) even if not bold.
        // Assuming base font is 16px.

        if (Number.isNaN(fontSize)) return true; // Can't determine

        if (fontSize >= 24) return false;
        if (isBold && fontSize >= 18) return false;

        return true;
    }
});

module.exports = [pNotHeading];
