const dom = require('../../utils/dom');

const check = {
    id: 'aria-command-name',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'ARIA command has an accessible name',
            fail: 'Command is missing an accessible name. Users won\'t know what action this command performs. Add `aria-label`, `aria-labelledby`, or visible text.'
        }
    },
    evaluate: function (node, options) {
        const name = dom.computeAccessibleName(node);
        return {
            pass: !!(name && name.trim().length > 0)
        };
    }
};

module.exports = [check];
