const check = {
    id: 'avoid-autofocus',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element does not have autofocus',
            fail: 'Autofocus attribute detected. Automatically moving focus can disorient screen reader and keyboard users. Remove the `autofocus` attribute.'
        }
    },
    selector: '[autofocus]',
    evaluate: function (node) {
        // The selector already finds elements with autofocus. 
        // So if this runs, it's a fail effectively, unless we want to checking something else?
        // Axe says: "Ensures that the autofocus attribute is not used."

        // Sometimes selector might match but attribute is empty or something? 
        // HTML attribute autofocus is boolean. Presence is enough.

        return {
            pass: false,
            message: 'The autofocus attribute causes focus to be moved automatically, which can be confusing for screen reader users.'
        };
    }
};

module.exports = [check];
