const dom = require('./dom');

const focusUtils = {
    /**
     * Check if an element is visible and enabled
     * @param {HTMLElement} element 
     */
    isVisibleAndEnabled: (element) => {
        if (!dom.isVisible(element)) return false;
        if (element.hasAttribute('disabled')) return false;
        if (element.getAttribute('aria-hidden') === 'true') return false; // Already checked in isVisible but double check usually safe

        // Fieldset disabled inheritance
        // (Simplified for now, real browser checks recursively up to fieldset[disabled])
        let current = element.parentElement;
        while (current) {
            if (current.tagName === 'FIELDSET' && current.hasAttribute('disabled')) {
                // The element is disabled unless it's in the <legend> of the disabled fieldset
                const legend = current.querySelector('legend');
                if (!legend || !legend.contains(element)) {
                    return false;
                }
            }
            current = current.parentElement;
        }

        return true;
    },

    /**
     * Check if element is focusable (tab index >= -1)
     * @param {HTMLElement} element 
     */
    isFocusable: (element) => {
        if (!focusUtils.isVisibleAndEnabled(element)) return false;

        const nodeName = element.nodeName.toLowerCase();
        const tabIndex = parseInt(element.getAttribute('tabindex'), 10);
        const hasTabIndex = !isNaN(tabIndex);

        if (hasTabIndex) return true;

        // Native focusable elements
        if (nodeName === 'a' && element.hasAttribute('href')) return true;
        if (nodeName === 'input' && element.type !== 'hidden') return true;
        if (['button', 'select', 'textarea'].includes(nodeName)) return true;
        if (nodeName === 'iframe') return true;
        if (element.hasAttribute('contenteditable')) return true;
        if (nodeName === 'area' && element.hasAttribute('href')) return true;
        if (nodeName === 'details' && !element.querySelector('summary')) return true; // Details without summary is often natively focusable in some browsers, or the summary is.
        // Actually, mostly logic checks for Summary, but let's stick to standard set.

        return false;
    },

    /**
     * Check if element is tabbable (tab index >= 0)
     * @param {HTMLElement} element 
     */
    isTabbable: (element) => {
        if (!focusUtils.isVisibleAndEnabled(element)) return false;

        const tabIndexAttr = element.getAttribute('tabindex');
        const tabIndex = parseInt(tabIndexAttr, 10);
        const hasTabIndex = !isNaN(tabIndex);

        if (hasTabIndex && tabIndex < 0) return false;

        // Valid tabindex >= 0 or default tabbable
        if (hasTabIndex && tabIndex >= 0) return true;

        const nodeName = element.nodeName.toLowerCase();

        if (nodeName === 'a' && element.hasAttribute('href')) return true;
        if (nodeName === 'input' && element.type !== 'hidden') return true;
        if (['button', 'select', 'textarea'].includes(nodeName)) return true;
        if (nodeName === 'iframe') return true;
        if (element.hasAttribute('contenteditable')) return true;
        if (nodeName === 'area' && element.hasAttribute('href')) return true;
        if (nodeName === 'summary') return true;

        return false;
    }
};

module.exports = focusUtils;
