const dom = require('../../utils/dom');

const check = {
    id: 'aria-treeitem-name',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'ARIA treeitem has an accessible name',
            fail: 'Tree item is missing an accessible name. Users cannot identify this item in the tree structure. Add `aria-label` or `aria-labelledby`.'
        }
    },
    evaluate: function (node, options) {
        const name = dom.computeAccessibleName(node);
        // Special case: treeitems might derive name from content if not explicit.
        // computeAccessibleName handles content calculation.
        return {
            pass: !!(name && name.trim().length > 0)
        };
    }
};

module.exports = [check];
