/**
 * Checks for image-alt
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasAlt = new Check({
    id: 'has-alt',
    metadata: {
        messages: {
            pass: 'Element has an alt attribute',
            fail: 'Image is missing an alternative text description. Screen readers cannot describe this image to users. Add an "alt" attribute with a descriptive text, or alt="" if decorative.'
        }
    },
    evaluate: function (node) {
        return node.hasAttribute('alt');
    }
});

const isPresentation = new Check({
    id: 'role-presentation',
    metadata: {
        messages: {
            pass: 'Element has role="presentation" or role="none"',
            fail: 'Element marked as decorative is missing role="presentation" or role="none". Screen readers might still announce it. Add role="none" or role="presentation" to ensure it is ignored.'
        }
    },
    evaluate: function (node) {
        const role = node.getAttribute('role');
        return role === 'presentation' || role === 'none';
    }
});

const hasAccessibleName = new Check({
    id: 'aria-label',
    metadata: {
        messages: {
            pass: 'Element has an accessible name via aria-label or aria-labelledby',
            fail: 'Element is missing an accessible name. Use `aria-label` or `aria-labelledby` if standard methods are not sufficient.'
        }
    },
    evaluate: function (node) {
        return !!dom.computeAccessibleName(node);
    }
});

module.exports = [hasAlt, isPresentation, hasAccessibleName];
