/**
 * Checks for page-has-heading-one
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const pageHasHeadingOne = new Check({
    id: 'page-has-heading-one',
    metadata: {
        messages: {
            pass: 'Page has a level-one heading',
            fail: 'Page is missing a level-one heading. Screen reader users rely on `<h1>` for main content identification. Ensure the page has exactly one visible `<h1>`.'
        }
    },
    evaluate: function (node) {
        const headings = Array.from(document.querySelectorAll('h1'));
        // Check if at least one h1 is visible
        return headings.some(h => dom.isVisible(h));
    }
});

module.exports = [pageHasHeadingOne];
