/**
 * Checks for label
 */
const Check = require('../../core/check');
const dom = require('../../utils/dom');

const hasLabel = new Check({
    id: 'form-field-has-label',
    metadata: {
        messages: {
            pass: 'Form field has an accessible label',
            fail: 'Form field is missing an accessible label. Users need a label to understand what input is required. Link a `<label>` using `for` attribute, or use `aria-label`/`aria-labelledby`.'
        }
    },
    evaluate: function (node) {
        const name = dom.computeAccessibleName(node);
        if (name) return true;

        const tag = node.tagName.toLowerCase();
        let typeInfo = '';
        if (tag === 'input') typeInfo = `<input type="${node.type}">`;
        else typeInfo = `<${tag}>`;

        return {
            pass: false,
            message: `This ${typeInfo} element is missing an accessible name. Users need a label to understand what input is required. Add a <label for="..."> or use aria-label.`
        };
    }
});

module.exports = [hasLabel];
