// Inject metadata from generated JSON if available
try {
    const generatedMetadata = require('./metadata.generated.json');
    rules.forEach(rule => {
        if (rule && rule.id && generatedMetadata[rule.id]) {
            const genMeta = generatedMetadata[rule.id];

            // 1. Rename Rule ID if specified in Excel (The Excel 'Rule ID' overrides the code 'id')
            if (genMeta.id) {
                rule.id = genMeta.id;
            }

            // 2. Apply Enable/Disable
            if (typeof genMeta.enabled === 'boolean') {
                rule.enabled = genMeta.enabled;
            }

            // 3. Apply Run on Hidden
            if (typeof genMeta.includeHidden === 'boolean') {
                rule.includeHidden = genMeta.includeHidden;
            }

            // 4. Overwrite metadata fields
            if (rule.metadata) {
                Object.assign(rule.metadata, genMeta.metadata);
            } else {
                rule.metadata = genMeta.metadata;
            }

            // 5. Overwrite tags if present in Excel
            if (genMeta.tags && genMeta.tags.length > 0) {
                rule.tags = genMeta.tags;
            }
        }
    });
} catch (e) {
    // Ignore if file doesn't exist (e.g. first run)
}

module.exports = rules;
