const check = {
    id: 'landmark-no-duplicate-contentinfo',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Page has only one contentinfo landmark',
            fail: 'Page must not have more than one contentinfo landmark'
        }
    },
    evaluate: function (node, options) {
        if (node.tagName !== 'HTML' && node.parentElement) return { pass: true };

        const candidates = document.querySelectorAll('footer, [role="contentinfo"]');
        let count = 0;

        for (let i = 0; i < candidates.length; i++) {
            const el = candidates[i];
            // Explicit role always counts
            if (el.getAttribute('role') === 'contentinfo') {
                count++;
            } else if (el.tagName === 'FOOTER') {
                // Implicit contentinfo if not inside sectioning content or main
                const scoped = el.closest('article, aside, main, nav, section');
                if (!scoped) {
                    count++;
                }
            }
        }

        if (count > 1) {
            return {
                pass: false,
                message: `Document must not have more than one contentinfo landmark. Found ${count}.`
            };
        }
        return { pass: true };
    }
};

module.exports = [check];
