module.exports = {
    id: 'document-title',
    selector: 'html',
    metadata: {
        description: 'Ensures each HTML document contains a non-empty <title> element. The title is the first thing screen reader users hear.',
        help: 'Documents must have <title> element to aid in navigation',
        helpUrl: 'https://dequeuniversity.com/rules/axe/4.4/document-title',
        impact: 'moderate'
    },
    tags: ['cat.text-alternatives', 'wcag2a', 'wcag242', 'gigw-3.0:5.2.28', 'is-17802:9.2.4.2'],
    any: ['doc-has-title'],
    checks: checks
};
