const check = {
    id: 'landmark-no-duplicate-banner',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Page has only one banner landmark',
            fail: 'Multiple banner landmarks detected. Screen reader users cannot identify the primary site header. Ensure only one `banner` landmark exists (typically `<header>` outside other landmarks).'
        }
    },
    evaluate: function (node, options) {
        if (node.tagName !== 'HTML' && node.parentElement) return { pass: true };

        const candidates = document.querySelectorAll('header, [role="banner"]');
        let count = 0;

        for (let i = 0; i < candidates.length; i++) {
            const el = candidates[i];
            if (el.getAttribute('role') === 'banner') {
                count++;
            } else if (el.tagName === 'HEADER') {
                // Implicit banner if not inside sectioning content or main
                const scoped = el.closest('article, aside, main, nav, section');
                if (!scoped) {
                    count++;
                }
            }
        }

        if (count > 1) {
            return {
                pass: false,
                message: `Document must not have more than one banner landmark. Found ${count}.`
            };
        }
        return { pass: true };
    }
};

module.exports = [check];
