const dom = require('../../utils/dom');

const check = {
    id: 'duplicate-id-active',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Active element ID is unique',
            fail: 'Duplicate ID on focusable element. Keyboard navigation and assistive technologies rely on unique IDs for active elements. Ensure valid, unique IDs for all interactive controls.'
        }
    },
    selector: 'a[href], button, input, select, textarea, [tabindex], details, summary',
    evaluate: function (node) {
        if (!node.hasAttribute('id')) return { pass: true };

        const id = node.getAttribute('id');
        if (!id) return { pass: true }; // empty id

        // Count occurrences in the document
        // Note: CSS selector escaping might be needed if ID has special chars, but for now standard check.
        // Or simpler: getElementById and check if it's strictly equal to node?
        // getElementById returns the *first* one.
        // If this node is the first one, we also need to know if there are *others*.

        // Robust way:
        const allWithId = node.ownerDocument.querySelectorAll(`[id="${id.replace(/"/g, '\\"')}"]`);
        if (allWithId.length > 1) {
            return {
                pass: false
                // Message comes from metadata
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
