/**
 * Checks for listitem
 */
const Check = require('../../core/check');

const listitem = new Check({
    id: 'listitem',
    metadata: {
        messages: {
            pass: 'List item has a valid parent',
            fail: 'List item is orphaned. Screen readers effectively ignore isolated list items. `<li>` elements must be children of `<ul>`, `<ol>`, or `<menu>`.'
        }
    },
    evaluate: function (node) {
        const parent = node.parentElement;
        if (!parent) return false;
        const validParents = ['UL', 'OL', 'MENU'];
        if (validParents.includes(parent.tagName)) return true;

        // Handle template/script wrapping? usually li is direct child. 
        // If wrapped in div inside look, that is invalid list structure usually? 
        // Standard says: ul/ol can contain li, script, template. 
        // li cannot be child of div inside ul. 
        // So strict parent check is usually correct.
        return false;
    }
});

module.exports = [listitem];
