const dom = require('../utils/dom');
const ResultBuilder = require('./result-builder');
const { getReporter } = require('./reporters');

class Runner {
    constructor(ruleManager, checkManager, configuration) {
        this.ruleManager = ruleManager;
        this.checkManager = checkManager;
        this.configuration = configuration;
        this.resultBuilder = new ResultBuilder();
        this.queue = [];
    }

    /**
     * Run all rules against the document
     * @param {Element|NodeList|String} context
     * @param {Object} options
     * @param {Function} callback
     * @returns {Promise<Object>}
     */
    async run(context, options = {}, callback) {
        // Handle optional arguments / Overloads
        // 1. run(options, callback) - context is implied document
        if (typeof options === 'function') {
            callback = options;
            options = {};
        }
        if (!options) options = {};

        // Resolve context
        let root;
        if (typeof document !== 'undefined') {
            root = document;
        }

        if (context) {
            // Check if context is actually options (Overload support)
            // Valid context: String, Node, or Object with .length (NodeList/jQuery)
            const isValidContext = (typeof context === 'string') ||
                (context.nodeType) ||
                (typeof context.length === 'number');

            if (!isValidContext && typeof context === 'object') {
                // Assume it is options
                // Merge with existing options if any? Usually replaces.
                options = { ...options, ...context };
                context = undefined; // Fallback to document
            }

            if (typeof context === 'string') {
                if (root) {
                    root = root.querySelector(context);
                } else {
                    throw new Error('Cannot query selector in an environment without a global document.');
                }
            } else if (typeof Node !== 'undefined' && context instanceof Node) {
                root = context;
            } else if (context && context.nodeType) {
                // Duck typing for Node if global Node is missing (rare but possible in some isolated VMs)
                root = context;
            }
        }

        if (!root) {
            if (typeof document === 'undefined') {
                throw new Error('Satya Engine: No context provided and no global document found. Please provide a root element or run in a browser/JSDOM environment.');
            }
            root = document;
        }

        this.resultBuilder.setOptions(options);

        // Start the run
        const runPromise = (async () => {
            // 1. Prepare exclusion list
            let excludes = [];
            if (options.exclude && Array.isArray(options.exclude)) {
                excludes = [...excludes, ...options.exclude];
            }

            // Check if iframe recursion is enabled (default true)
            const iframesEnabled = options.iframes !== false;

            // 1. Crawl the DOM to find all nodes and their contexts
            const nodes = await this.crawl(root, excludes, iframesEnabled);

            // 2. Get active rules
            const rules = this.getRulesToRun(options);

            // 3. Run rules against nodes
            for (const rule of rules) {
                try {
                    // Filter nodes that match the selector
                    const matchingNodes = nodes.filter(node => {
                        try {
                            const m = rule.matches(node, dom);
                            return m;
                        } catch (e) {
                            // console.warn(`Rule ${rule.id} failed to match node`, e);
                            return false;
                        }
                    });

                    // Filter out hidden nodes or other non-applicable nodes
                    const runnableNodes = matchingNodes.filter(node => {
                        try {
                            if (rule.includeHidden) return true;
                            const vis = dom.isVisible(node);
                            return vis;
                        } catch (e) {
                            return false;
                        }
                    });

                    if (runnableNodes.length === 0) {
                        this.resultBuilder.addInapplicable(rule);
                        continue;
                    }

                    for (const node of runnableNodes) {
                        try {
                            const result = await this.runRule(rule, node, options, node._frameStack);
                            this.resultBuilder.addResult(rule, result.nodeInfo, result.status);
                        } catch (e) {
                            // If an individual check fails on a specific node, catch it and log error
                            this.resultBuilder.addResult(rule, {
                                html: dom.getSnippet(node),
                                target: [[...(node._frameStack || []), dom.getSelector(node)].join(' > ')],
                                failureSummary: `Internal Error: ${e.message}`
                            }, 'incomplete');
                        }
                    }
                } catch (err) {
                    console.error(`Rule ${rule.id} crashed unexpectedly:`, err.message);
                    // Add a generic failure result so it shows up in reports? 
                    // Or just skip it safely?
                    // Let's mark it as incomplete/error in results if possible, or just log it.
                    // Ideally, we shouldn't have rules crashing at the top level, but better safe.
                }
            }

            // 4. Run Focus Analysis (On-Demand)
            if (options.focusOrder) {
                try {
                    const FocusAnalyzer = require('./focus-analyzer');
                    const tabOrder = FocusAnalyzer.getTabOrder(root);
                    this.resultBuilder.setMetadata('focusOrder', tabOrder);
                } catch (e) {
                    // console.warn('Focus analysis failed', e);
                    this.resultBuilder.setMetadata('focusOrderError', e.message);
                }
            }

            // 5. Capture Screenshot (On-Demand)
            if (options.screenshot) {
                const provider = options.screenshotProvider || this.configuration.screenshotProvider;
                if (provider && typeof provider === 'function') {
                    try {
                        const screenshotData = await provider();
                        this.resultBuilder.setMetadata('screenshot', screenshotData);
                    } catch (e) {
                        // resilience: failure must not affect flow
                        // console.warn('Screenshot capture failed', e);
                        this.resultBuilder.setMetadata('screenshotError', e.message);
                    }
                } else {
                    // Provider missing
                    this.resultBuilder.setMetadata('screenshotError', 'No screenshotProvider configured');
                }
            }

            const results = this.resultBuilder.getResults();
            const reporter = getReporter(options.reporter || 'v1');
            return reporter(results, options);
        })();

        if (callback) {
            runPromise.then(results => callback(null, results)).catch(err => callback(err));
        }

        return runPromise;
    }

    /**
     * Crawl the DOM including iframes and shadow roots
     * @param {Node} root 
     * @param {string[]} excludeSelectors - List of selectors to exclude
     * @param {boolean} iframesEnabled - Whether to recurse into iframes
     * @returns {Promise<Node[]>}
     */
    async crawl(root, excludeSelectors = [], iframesEnabled = true) {
        const nodes = [];
        const queue = [root];
        const visited = new Set();
        visited.add(root);

        while (queue.length > 0) {
            const node = queue.shift();

            // Check exclusions for elements
            if (node.nodeType === 1 && excludeSelectors.length > 0) {
                const isExcluded = excludeSelectors.some(selector => dom.matches(node, selector));
                if (isExcluded) continue;
            }

            // Add current node if it's an element
            if (node.nodeType === 1) {
                nodes.push(node);
            }

            // Handle Shadow DOM
            if (node.shadowRoot) {
                // We treat shadow root children as part of the document
                const shadowChildren = Array.from(node.shadowRoot.querySelectorAll('*'));
                shadowChildren.forEach(child => {
                    if (!visited.has(child)) {
                        visited.add(child);
                        queue.push(child);
                    }
                });
            }

            // Handle IFrames
            if (iframesEnabled && (node.tagName === 'IFRAME' || node.tagName === 'FRAME')) {
                // Skip hidden iframes (check visibility and dimensions)
                if (!dom.isVisible(node)) continue;
                if (node.offsetWidth === 0 && node.offsetHeight === 0) continue;

                try {
                    const doc = node.contentDocument;
                    if (doc) {
                        const iframeChildren = Array.from(doc.querySelectorAll('*'));
                        // Add frame stack info to children
                        const frameSelector = dom.getSelector(node);
                        const parentStack = node._frameStack || [];
                        const currentStack = [...parentStack, frameSelector];

                        iframeChildren.forEach(child => {
                            if (!visited.has(child)) {
                                child._frameStack = currentStack;
                                visited.add(child);
                                queue.push(child);
                            }
                        });
                    }
                } catch (e) {
                    // Cross-origin iframe access blocked
                    // console.warn('Cannot access iframe content', e);
                }
            }

            // Add children to queue (Standard DOM traversal)
            // This ensures that if we exclude a node (continue above), its children are never added.
            if (node.children) {
                const children = Array.from(node.children);
                children.forEach(child => {
                    if (!visited.has(child)) {
                        visited.add(child);
                        queue.push(child);
                    }
                });
            }
        }

        return nodes;
    }

    /**
     * Get rules filtered by options
     * @param {Object} options 
     */
    getRulesToRun(options) {
        const rules = this.ruleManager.getRules();
        return rules.filter(rule => {
            if (rule.enabled === false) return false;

            // RunOnly logic
            if (options.runOnly) {
                if (options.runOnly.type === 'rule' && !options.runOnly.values.includes(rule.id)) {
                    return false;
                }
                if (options.runOnly.type === 'tag') {
                    const hasTag = rule.tags.some(tag => options.runOnly.values.includes(tag));
                    if (!hasTag) return false;
                }
            }
            return true;
        });
    }

    /**
     * Run a single rule against a node
     * @param {Rule} rule 
     * @param {HTMLElement} node 
     * @param {Object} options 
     */
    async runRule(rule, node, options, frameStack = []) {
        // Legacy support
        if (rule.runFn || rule.check) {
            const result = rule.run(node, options);
            return {
                status: result.status,
                nodeInfo: {
                    html: dom.getSnippet(node),
                    target: [[...frameStack, dom.getSelector(node)].join(' > ')],
                    rect: options.highlight ? dom.getRect(node) : undefined,
                    failureSummary: result.message,
                    any: [],
                    all: [],
                    none: []
                }
            };
        }

        // New Check System
        const anyResults = await this.evaluateChecks(rule.any, node, options);
        const allResults = await this.evaluateChecks(rule.all, node, options);
        const noneResults = await this.evaluateChecks(rule.none, node, options);

        // Determine status
        let status = 'pass';
        let failureMessages = [];
        let incompleteMessages = [];

        // Any: At least one must pass
        if (rule.any.length > 0) {
            const passed = anyResults.some(r => r.status === 'pass');
            if (!passed) {
                const incomplete = anyResults.some(r => r.status === 'incomplete');
                if (incomplete) {
                    status = 'incomplete';
                    incompleteMessages.push(...anyResults.filter(r => r.status === 'incomplete').map(r => r.message));
                } else {
                    status = 'fail';
                    failureMessages.push(...anyResults.map(r => r.message));
                }
            }
        }

        // All: All must pass
        if (rule.all.length > 0) {
            const failed = allResults.filter(r => r.status === 'fail');
            if (failed.length > 0) {
                status = 'fail';
                failureMessages.push(...failed.map(r => r.message));
            } else {
                const incomplete = allResults.filter(r => r.status === 'incomplete');
                if (incomplete.length > 0) {
                    status = 'incomplete';
                    incompleteMessages.push(...incomplete.map(r => r.message));
                }
            }
        }

        // None: None must pass (all must fail)
        if (rule.none.length > 0) {
            const passed = noneResults.filter(r => r.status === 'pass');
            if (passed.length > 0) {
                status = 'fail';
                failureMessages.push(...passed.map(r => r.message)); // Message should explain why it shouldn't pass
            } else {
                const incomplete = noneResults.filter(r => r.status === 'incomplete');
                if (incomplete.length > 0) {
                    status = 'incomplete';
                    incompleteMessages.push(...incomplete.map(r => r.message));
                }
            }
        }

        // Check for "Needs Review" override
        if (status === 'fail' && rule.metadata && rule.metadata.needsReview) {
            status = 'incomplete';
            incompleteMessages.push(...failureMessages);
            failureMessages = [];
        }

        return {
            status: status,
            nodeInfo: {
                html: dom.getSnippet(node),
                target: [[...frameStack, dom.getSelector(node)].join(' > ')],
                rect: options.highlight ? dom.getRect(node) : undefined,
                any: anyResults,
                all: allResults,
                none: noneResults,
                failureSummary: status === 'fail' ? failureMessages.join(' OR ') : (status === 'incomplete' ? incompleteMessages.join(' OR ') : undefined)
            }
        };
    }

    /**
     * Evaluate a list of checks
     * @param {string[]} checkIds 
     * @param {HTMLElement} node 
     * @param {Object} options 
     */
    async evaluateChecks(checkIds, node, options) {
        const results = [];
        for (const id of checkIds) {
            const check = this.checkManager.getCheck(id);
            if (!check) {
                console.warn(`Check not found: ${id}`);
                continue;
            }

            try {
                const result = check.run(node, options);
                // Normalize result
                let status = 'fail';
                if (result === true || (result && result.pass === true)) {
                    status = 'pass';
                    // We need to support 'incomplete' return from check too
                } else if (result && result.incomplete === true) {
                    status = 'incomplete';
                }

                // If check threw error, result object might not match exactly, 
                // but we caught it below. Here we handle normal returns.

                const message = (result && result.message) || check.metadata.messages?.[status] || (status === 'pass' ? 'Check passed' : 'Check failed');

                results.push({
                    id: id,
                    status: status,
                    result: status === 'pass', // Legacy compatibility
                    message: message,
                    data: result && result.data
                });
            } catch (e) {
                results.push({
                    id: id,
                    status: 'fail',
                    result: false,
                    message: `Error executing check: ${e.message}`
                });
            }
        }
        return results;
    }
}

module.exports = Runner;
