const check = {
    id: 'no-autoplay-audio',
    metadata: {
        impact: 'critical', // Autoplay is very disruptive
        messages: {
            pass: 'Element does not autoplay',
            fail: 'Element has the `autoplay` attribute. Remove it to avoid disrupting users.'
        }
    },
    selector: 'audio, video',
    evaluate: function (node) {
        // Check for autoplay attribute
        if (node.hasAttribute('autoplay')) {
            // Exceptions? 
            // If the audio is muted, maybe less severe, but still potentially distracting (video).
            // Axe: "Ensures <video> or <audio> elements do not autoplay audio for more than 3 seconds without a control mechanism to stop or mute the audio."
            // Simple check: presence of autoplay is a potential violation.
            // Strict interpretation: fail if autoplay is present.

            return {
                pass: false,
                message: 'The element autoplays media, which can be disruptive for users.'
            };
        }
        return { pass: true };
    }
};

module.exports = [check];
