const check = {
    id: 'aria-hidden-focus',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Element is hidden and not focusable',
            fail: 'Hidden element contains focusable content. Keyboard users might focus on elements that are hidden from screen readers. Ensure `aria-hidden="true"` is not used on focusable elements.'
        }
    },
    evaluate: function (node, options) {
        // Helper to check focusability
        function isFocusable(el) {
            if (el.hasAttribute('tabindex') && parseInt(el.getAttribute('tabindex')) >= 0) return true;
            const tag = el.tagName.toLowerCase();
            const focusableTags = ['a', 'button', 'input', 'select', 'textarea', 'details', 'embed', 'iframe', 'label', 'audio', 'video'];
            if (focusableTags.includes(tag)) {
                if (tag === 'a' && !el.hasAttribute('href')) return false;
                return true;
            }
            return false;
        }

        if (isFocusable(node)) {
            return { pass: false, message: 'Focusable element is aria-hidden' };
        }

        // Search descendants
        const focusableDescendants = node.querySelectorAll('a[href], button, input, select, textarea, [tabindex]:not([tabindex="-1"])');
        if (focusableDescendants.length > 0) {
            return { pass: false, message: 'Element contains focusable descendants' };
        }

        return { pass: true };
    }
};

module.exports = [check];
