const dom = require('../../utils/dom');

const check = {
    id: 'aria-progressbar-name',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'ARIA progressbar has an accessible name',
            fail: 'Progressbar is missing an accessible name. Users won\'t know what the progress bar tracks. Add `aria-label` or `aria-labelledby`.'
        }
    },
    evaluate: function (node, options) {
        const name = dom.computeAccessibleName(node);
        return {
            pass: !!(name && name.trim().length > 0)
        };
    }
};

module.exports = [check];
