const check = {
    id: 'interactive-supports-focus',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Interactive element is focusable',
            fail: 'Element has an interactive role but is not focusable. Add tabindex="0" to make it keyboard accessible.'
        }
    },
    selector: '[role]',
    evaluate: function (node) {
        const role = node.getAttribute('role');
        if (!role) return { pass: true };

        // List of interactive roles that require focus
        // Based on WAI-ARIA 1.1/1.2
        const interactiveRoles = [
            'button', 'link', 'checkbox', 'menuitem', 'menuitemcheckbox',
            'menuitemradio', 'option', 'radio', 'searchbox', 'switch', 'tab',
            'textbox', 'combobox', 'gridcell', 'slider', 'spinbutton', 'treeitem'
        ];

        if (!interactiveRoles.includes(role)) {
            return { pass: true };
        }

        // Check if natively focusable
        const nodeName = node.nodeName.toUpperCase();
        if (nodeName === 'BUTTON' ||
            nodeName === 'INPUT' ||
            nodeName === 'SELECT' ||
            nodeName === 'TEXTAREA') {
            if (!node.hasAttribute('disabled')) return { pass: true };
        }
        if (nodeName === 'A' && node.hasAttribute('href')) return { pass: true };
        if (nodeName === 'AREA' && node.hasAttribute('href')) return { pass: true };

        // Check tabindex
        if (node.hasAttribute('tabindex')) {
            // Simply having tabindex makes it focusable (programmatically or keyboard)
            return { pass: true };
        }

        // Check contenteditable
        if (node.hasAttribute('contenteditable') && node.getAttribute('contenteditable') !== 'false') {
            return { pass: true };
        }

        return {
            pass: false,
            message: `The element with role="${role}" is not focusable. Add tabindex="0" to make it focusable.`
        };
    }
};

module.exports = [check];
