const dom = require('../../utils/dom');

// Helper to get role (simplified)
function getRole(node) {
    if (node.hasAttribute('role')) {
        return node.getAttribute('role');
    }
    const tagName = node.tagName.toLowerCase();

    if (tagName === 'main') return 'main';
    if (tagName === 'nav') return 'navigation';
    if (tagName === 'aside') return 'complementary';
    if (tagName === 'header') {
        // banner if not descendant of sectioning content
        // JSDOM supports closest. Check parent context.
        if (node.parentElement && !node.parentElement.closest('article, aside, main, nav, section')) return 'banner';
        // If no parent (root), it is banner.
        if (!node.parentElement) return 'banner';
        return null; // It's scoped
    }
    if (tagName === 'footer') {
        // contentinfo if not descendant of sectioning content
        if (node.parentElement && !node.parentElement.closest('article, aside, main, nav, section')) return 'contentinfo';
        if (!node.parentElement) return 'contentinfo';
        return null;
    }
    if (tagName === 'section') {
        if (node.hasAttribute('aria-label') || node.hasAttribute('aria-labelledby')) return 'region';
    }
    if (tagName === 'form') {
        if (node.hasAttribute('aria-label') || node.hasAttribute('aria-labelledby')) return 'form';
    }
    if (tagName === 'search') return 'search';

    return null;
}

const check = {
    id: 'landmark-banner-is-top-level',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Banner landmark is top-level',
            fail: 'Banner landmark must not be contained in another landmark'
        }
    },
    selector: 'header, [role="banner"]',
    evaluate: function (node) {
        // 1. Determine if this IS a banner.
        const role = getRole(node);
        if (role !== 'banner') return { pass: true }; // Not a banner checking instance (e.g. header inside article)

        // 2. Check ancestors
        let parent = node.parentElement;
        const landmarkRoles = ['application', 'banner', 'complementary', 'contentinfo', 'form', 'main', 'navigation', 'region', 'search'];

        while (parent && parent.nodeType === 1) { // Node.ELEMENT_NODE
            const pRole = getRole(parent);
            if (pRole && landmarkRoles.includes(pRole)) {
                return {
                    pass: false,
                    message: `Banner landmark is contained in ${pRole} landmark`
                };
            }
            parent = parent.parentElement;
        }

        return { pass: true };
    }
};

module.exports = [check];

