const dom = require('../../utils/dom');

function isLandmark(element) {
    if (!element || element.nodeType !== 1) return false;

    const role = element.getAttribute('role');
    const tagName = element.tagName.toLowerCase();

    // Explicit roles
    const landmarkRoles = ['banner', 'complementary', 'contentinfo', 'form', 'main', 'navigation', 'region', 'search', 'application'];
    if (role && landmarkRoles.includes(role)) return true;

    // Implicit roles
    if (tagName === 'main' || tagName === 'nav' || tagName === 'aside' || tagName === 'header' || tagName === 'footer') return true;

    // Section with name is a region (landmark)
    if (tagName === 'section' && (element.hasAttribute('aria-label') || element.hasAttribute('aria-labelledby'))) return true;

    // Form with name is a form landmark
    if (tagName === 'form' && (element.hasAttribute('aria-label') || element.hasAttribute('aria-labelledby'))) return true;

    return false;
}

const check = {
    id: 'landmark-main-is-top-level',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'Main landmark is top-level',
            fail: 'Main landmark is nested. The `main` region must be top-level to be easily reachable. Move the `<main>` element outside of other landmarks.'
        }
    },
    selector: 'main, [role="main"]',
    evaluate: function (node) {
        // Check hierarchy
        let current = node.parentElement;
        while (current && current.tagName.toLowerCase() !== 'html') {
            if (isLandmark(current)) {
                return {
                    pass: false,
                    message: `Main landmark is contained in ${current.tagName} (role: ${current.getAttribute('role') || 'implicit'})`
                };
            }
            current = current.parentElement;
        }
        return { pass: true };
    }
};

module.exports = [check];
