/**
 * Check definition for Satya Engine
 * Represents a granular test that can be reused across rules.
 */
class Check {
    constructor(config) {
        this.id = config.id;
        this.metadata = config.metadata || {};
        this.evaluate = config.evaluate;
        this.after = config.after; // Optional cleanup/post-processing
    }

    /**
     * Run the check against a node
     * @param {HTMLElement} node
     * @param {Object} options
     * @param {Object} virtualNode - Optional virtual DOM node
     * @returns {Boolean|Object} Result
     */
    run(node, options, virtualNode) {
        if (!this.evaluate) {
            throw new Error(`Check ${this.id} has no evaluate function`);
        }
        return this.evaluate.call(this, node, options, virtualNode);
    }
}

module.exports = Check;
