const dom = require('../../utils/dom');

const check = {
    id: 'bypass',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Page has a means to bypass repeated blocks',
            fail: 'Page is missing a bypass mechanism. Keyboard users need a way to skip repeated headers or navigation. Add a skip link, landmark regions, or collapsible menus.'
        }
    },
    evaluate: function (node, options) {
        const doc = node.ownerDocument;

        // 1. Check for main landmark
        const main = doc.querySelector('main, [role="main"]');
        if (main) return { pass: true };

        // 2. Check for skip link (first focusable element is a link to an anchor)
        // For simplicity, we check if ANY link points to an ID on the page and is visible
        // Ideally, it should be the first focusable element.
        const links = Array.from(doc.querySelectorAll('a[href^="#"]'));
        for (const link of links) {
            const id = link.getAttribute('href').slice(1);
            if (id && doc.getElementById(id)) {
                // Check if link is potentially a skip link (heuristic: visually hidden until focus, or at top)
                // We will accept valid internal links as "potential" bypass mechanisms for this engine version.
                return { pass: true };
            }
        }

        return { pass: false };
    }
};

module.exports = [check];
