const dom = require('../../utils/dom');

const check = {
    id: 'region',
    metadata: {
        impact: 'moderate',
        messages: {
            pass: 'All content is contained by landmarks',
            fail: 'This element contains content that is not wrapped in a landmark region. Screen reader users rely on landmarks (like <main>, <nav>, <footer>) to navigate content effectively. Note: We only flag this container element to avoid noise, but all its direct content is technically outside valid regions.'
        }

    },
    evaluate: function (node, options) {
        // Now 'node' is an arbitrary element because selector is '*'

        // Helper to identify landmarks
        function isLandmark(element) {
            const landmarkRoles = ['banner', 'complementary', 'contentinfo', 'form', 'main', 'navigation', 'region', 'search', 'dialog', 'alertdialog', 'application'];
            const role = element.getAttribute('role');
            const tag = element.tagName.toLowerCase();

            if (role && landmarkRoles.includes(role)) return true;
            if (tag === 'main' || tag === 'nav' || tag === 'aside' || tag === 'header' || tag === 'footer') return true;
            if (tag === 'form' || (tag === 'section' && element.hasAttribute('aria-label'))) return true;
            return false;
        }

        // Helper to check if node is inside a landmark
        function isInsideLandmark(element) {
            let current = element.parentElement; // Start checking from parent
            while (current && current.tagName.toLowerCase() !== 'html') {
                if (isLandmark(current)) return true;
                current = current.parentElement;
            }
            return false;
        }

        // Helper to check if node contains a landmark
        function containsLandmark(element) {
            // Select all possible landmarks
            const landmarkRoles = ['banner', 'complementary', 'contentinfo', 'form', 'main', 'navigation', 'region', 'search', 'dialog', 'alertdialog', 'application'];
            const rolesSelector = landmarkRoles.map(r => `[role="${r}"]`).join(',');
            const tagsSelector = 'main, nav, aside, header, footer, form, section[aria-label]';
            const selector = `${rolesSelector}, ${tagsSelector}`;

            // Check descendants
            return element.querySelectorAll(selector).length > 0;
        }

        // Helper to check if subtree has content (text/widgets) - skipping landmarks
        function hasContent(element) {
            // If the element itself is a landmark (nested case), we shouldn't be here typically because 
            // we stop recursion at landmarks. But if called on root node:
            // Actually, if 'element' is passed, we check its contents.

            const childNodes = element.childNodes;
            for (let i = 0; i < childNodes.length; i++) {
                const child = childNodes[i];

                if (child.nodeType === 3) { // Text node
                    if (child.textContent.trim().length > 0) return true;
                } else if (child.nodeType === 1) { // Element
                    // If child is a landmark, we SKIP it fully. Its content is "contained".
                    if (isLandmark(child)) continue;

                    // If child is explicitly hidden, skip
                    if (!dom.isVisible(child)) continue;

                    // Check if child is a widget
                    const tagName = child.tagName.toLowerCase();
                    const isWidget = ['input', 'select', 'textarea', 'button', 'img', 'object', 'iframe', 'canvas', 'video', 'audio'].includes(tagName);
                    if (isWidget) return true;

                    // Recurse
                    if (hasContent(child)) return true;
                }
            }
            return false;
        }

        const tagName = node.tagName.toLowerCase();
        const ignoreTags = ['script', 'style', 'template', 'noscript', 'meta', 'link', 'title', 'head', 'html', 'body'];
        if (ignoreTags.includes(tagName)) return { pass: true };

        // Check visibility
        if (!dom.isVisible(node)) return { pass: true };

        // Check content presence (recursive, so empty containers are skipped unless they contain widgets/text)
        if (!hasContent(node)) return { pass: true };

        // Define "Orphan Root" logic
        // An element is an orphan if it is NOT a landmark AND it is NOT inside a landmark AND it does NOT contain a landmark.
        // If it contains a landmark, it passes validation itself (as a container), and we look deeper for specific siblings.
        function isOrphan(el) {
            if (!el || el.tagName === 'BODY' || el.tagName === 'HTML') return false;
            // We assume body/html are never "orphans" in the sense that they are the root context. 
            // If body has content and no landmarks, body is the parent of the orphan root.

            // Check intrinsic properties
            if (isLandmark(el)) return false;
            if (isInsideLandmark(el)) return false;
            // Check containment
            // if (containsLandmark(el)) return false; // REMOVED: We now rely on hasContent skipping landmarks. 
            // If we have content (handled by hasContent), and it's not a landmark or inside one, it's an orphan.

            return true;
        }

        // Logic:
        // 1. If I am not an orphan -> Pass.
        // 1. If I am not an orphan -> Pass.
        if (!isOrphan(node)) return { pass: true };

        if (!isOrphan(node)) return { pass: true };


        // 2. I am an orphan.
        // 3. Is my parent an orphan?
        // If parent is an orphan, parent captures the violation. I should pass.
        // If parent is NOT an orphan (e.g. parent contains nested landmark), then parent passed.
        // I am the "start" of the orphan branch inside that parent.
        if (node.parentElement && isOrphan(node.parentElement)) {
            return { pass: true };
        }

        // 4. Else -> Fail
        return {
            pass: false,
            message: 'This element contains content that is not wrapped in a landmark region. Screen reader users rely on landmarks (like <main>, <nav>, <footer>) to navigate content effectively. Note: We only flag this container element to avoid noise, but all its direct content is technically outside valid regions.'
        };

    }
};

module.exports = [check];
