const check = {
    id: 'aria-required-attr',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Required ARIA attributes are present',
            fail: 'Required ARIA attribute is missing. The element\'s role requires specific attributes to function correctly. Check WAI-ARIA specs and add the missing attribute(s).'
        }
    },
    evaluate: function (node, options) {
        const { roles } = require('../../utils/aria-definitions');
        const explicitRole = node.getAttribute('role');

        if (!explicitRole) return { pass: true };

        // Handle multiple roles (space-separated)
        const roleList = explicitRole.split(/\s+/).filter(r => r.length > 0);
        let role = null;

        // Use the first valid role
        for (const candidate of roleList) {
            if (roles[candidate]) {
                role = candidate;
                break;
            }
        }

        if (!role) return { pass: true };

        const { isAttributeSatisfiedByNative } = require('../../utils/aria-utils');
        const required = roles[role].required || [];
        const missing = [];

        for (const req of required) {
            if (!node.hasAttribute(req) && !isAttributeSatisfiedByNative(node, req)) {
                missing.push(req);
            }
        }

        if (missing.length > 0) {
            return {
                pass: false,
                message: `Required attributes missing for role "${role}": ${missing.join(', ')}`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
