class PluginManager {
    constructor(engine) {
        this.engine = engine;
        this.plugins = new Set();
    }

    /**
     * Register a plugin
     * @param {Object} plugin 
     */
    register(plugin) {
        if (this.plugins.has(plugin)) {
            return;
        }

        if (typeof plugin.id !== 'string') {
            throw new Error('Plugin must have an ID');
        }

        // Execute plugin initialization if present
        if (typeof plugin.run === 'function') {
            plugin.run(this.engine);
        }

        // Register rules if the plugin provides them
        if (Array.isArray(plugin.rules)) {
            plugin.rules.forEach(rule => this.engine.addRule(rule));
        }

        this.plugins.add(plugin);
    }

    /**
     * Clear all plugins
     */
    clear() {
        this.plugins.clear();
    }
}

module.exports = PluginManager;
