const check = {
    id: 'frame-title-unique',
    metadata: {
        impact: 'serious',
        messages: {
            pass: 'Frame title is unique',
            fail: 'Frame title is not unique. Screen reader users cannot distinguish between frames. Ensure all `<iframe>` titles are unique.'
        }
    },
    selector: 'iframe, frame',
    evaluate: function (node) {
        if (!node.hasAttribute('title')) {
            // If no title, it's not a duplicate title issue (might be frame-title issue though).
            // Pass this rule, fail frame-title rule.
            return { pass: true };
        }

        const title = node.getAttribute('title');
        if (!title.trim()) return { pass: true }; // empty title handled elsewhere

        // Find all frames with this title
        // We need to escape quotes in title for selector
        const updatesTitle = title.replace(/"/g, '\\"');
        const selector = `iframe[title="${updatesTitle}"], frame[title="${updatesTitle}"]`;
        const matches = node.ownerDocument.querySelectorAll(selector);

        if (matches.length > 1) {
            return {
                pass: false,
                message: `Non-unique frame title detected. Users cannot distinguish between frames. Ensure the title "${title}" is unique among all frames on the page.`
            };
        }

        return { pass: true };
    }
};

module.exports = [check];
